_DAILY_TRACKING_COMPLETED_COLORS = {"#3b82f6"}
_DAILY_TRACKING_NO_TRACK_COLORS = {"#ef4444"}


def _daily_tracking_category_from_color(color: str) -> str:
    normalized = color.lower()
    if normalized in {c.lower() for c in _DAILY_TRACKING_CONTINUE_COLORS}:
        return "Takibe Devam Edilecek"
    if normalized in {c.lower() for c in _DAILY_TRACKING_MEETING_COLORS}:
        return "Görüşme Ekranına Aktarılacak"
    if normalized in {c.lower() for c in _DAILY_TRACKING_COMPLETED_COLORS}:
        return "Tamamlanmış (Salt Okunur)"
    if normalized in {c.lower() for c in _DAILY_TRACKING_NO_TRACK_COLORS}:
        return "Takip Edilmeyecek"
    return "Takibe Devam Edilecek"


def _coerce_to_date(value: Any) -> date | None:
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, date):
        return value
    return None


def _daily_tracking_date_range(option: str, today: date) -> tuple[date, date]:
    if option == "Dün":
        yesterday = today - timedelta(days=1)
        return yesterday, yesterday
    if option == "Hafta":
        return today - timedelta(days=6), today
    if option == "Ay":
        return today.replace(day=1), today
    if option == "Yıl":
        return today.replace(month=1, day=1), today
    return today - timedelta(days=6), today


def _daily_tracking_status_label(color: str, normalized_status: str) -> str:
    special = {
        "#16a34a": "Henüz aranmadı",
        "#059669": "Henüz aranmadı",
        "#22c55e": "Henüz aranmadı",
        "#2563eb": "Tekrar ara",
        "#db2777": "Tekrar ara",
    }
    lower_color = color.lower()
    if lower_color in special:
        return special[lower_color]
    if not normalized_status:
        return "Hiç arama yapılmadı"
    return FOLLOWUP_STATUS_DISPLAY_MAP.get(
        normalized_status,
        normalized_status.title() if normalized_status else "Durum bilinmiyor",
    )

