def _kampanya_oncelik_sirasi(kampanya_adi: str) -> int:
    """Kampanya adına göre öncelik sırası döndürür (düşük = öncelikli)."""
    kampanya_lower = kampanya_adi.lower()
    for oncelik, anahtar_kelimeler in KAMPANYA_ONCELIK_ANAHTAR_KELIMELERI.items():
        for kelime in anahtar_kelimeler:
            if kelime.lower() in kampanya_lower:
                return oncelik
    return 5  # Tanımlanmamış kampanyalar en sona


def _sirala_kampanyalar(kampanya_listesi: list[str]) -> list[str]:
    """Kampanya listesini öncelik sırasına göre sıralar."""
    return sorted(kampanya_listesi, key=_kampanya_oncelik_sirasi)


