def _purpose_for_item(item: str) -> str:
    return PURPOSE_MAP.get(item, item)


def _limit_burs_items(month_name: str, items: list[str]) -> list[str]:
    burs_items = [item for item in items if "Burs" in item or "burs" in item]
    if not burs_items:
        return items
    if month_name == "Ocak":
        return items
    return [item for item in items if item not in burs_items]

