# ==================== GENERIC IO ====================


def load_json_list(path: str) -> list[dict[str, Any]]:
    if not os.path.exists(path):
        return []
    try:
        with open(path, "r", encoding="utf-8") as handle:
            payload = json.load(handle)
        return payload if isinstance(payload, list) else []
    except Exception:
        return []


def save_json_list(path: str, items: list[dict[str, Any]]) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as handle:
        json.dump(items, handle, ensure_ascii=False, indent=2)


def load_json_dict(path: str) -> dict[str, Any]:
    if not os.path.exists(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8") as handle:
            payload = json.load(handle)
        return payload if isinstance(payload, dict) else {}
    except Exception:
        return {}


def load_tracking_history() -> dict[str, list[dict[str, Any]]]:
    raw = load_json_dict(get_pr01_tracking_history_path())
    cleaned: dict[str, list[dict[str, Any]]] = {}
    for key, value in raw.items():
        if isinstance(value, list):
            cleaned[key] = value
    return cleaned


def save_tracking_history(history: dict[str, list[dict[str, Any]]]) -> None:
    save_json_dict(get_pr01_tracking_history_path(), history)


def load_meeting_results() -> list[dict[str, Any]]:
    return load_json_list(get_pr01_meeting_results_path())


def save_meeting_results(results: list[dict[str, Any]]) -> None:
    save_json_list(get_pr01_meeting_results_path(), results)


def load_liste_fiyatlari() -> dict[str, Any]:
    """Kurum liste fiyatlarını yükle (yılda 1 kez girilir, tüm adaylarda ortak)."""
    return load_json_dict(get_pr01_liste_fiyatlari_path())


def save_liste_fiyatlari(data: dict[str, Any]) -> None:
    """Kurum liste fiyatlarını kaydet."""
    path = get_pr01_liste_fiyatlari_path()
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as handle:
        json.dump(data, handle, ensure_ascii=False, indent=2)


