    _ilan_toplam = 0.0
    _ilan_toplam_kdv = 0.0
    _ogr_toplam = 0.0
    _ogr_toplam_kdv = 0.0
    _rows_y_top = y + 0.15 * cm

    for row_idx, (lf_key, label, sozlesme_key_ucret, veli_istegi) in enumerate(_ucret_map):
        _check(0.8 * cm)
        # Zebra arka plan
        if row_idx % 2 == 0:
            c.setFillColorRGB(*ROW_ALT)
            c.rect(margin_l, y - 0.2 * cm, _tbl_right - margin_l, _row_h, fill=True, stroke=False)

        # İlan edilen
        ilan_ucret = float(_lf_pdf.get(lf_key, 0))
        ilan_kdv = ilan_ucret * (_kdv_oran / 100)
        ilan_toplam_row = ilan_ucret + ilan_kdv
        _ilan_toplam += ilan_ucret
        _ilan_toplam_kdv += ilan_toplam_row

        # Öğrenci için belirlenen
        try:
            ogr_ucret = float(sozlesme.get(sozlesme_key_ucret, 0) or 0)
        except (ValueError, TypeError):
            ogr_ucret = 0.0
        ogr_kdv = ogr_ucret * (_kdv_oran / 100)
        ogr_toplam_row = ogr_ucret + ogr_kdv
        _ogr_toplam += ogr_ucret
        _ogr_toplam_kdv += ogr_toplam_row

        c.setFillColorRGB(*DARK_TEXT)
        _tbl_cell(label, 0, y, size=6.5)
        _tbl_cell(f"{ilan_ucret:,.0f}" if ilan_ucret else "", 1, y, size=6.5, align="right")
        _tbl_cell(f"%{_kdv_oran:.0f}" if ilan_ucret else "", 2, y, size=6, align="center", color=GRAY_TEXT)
        _tbl_cell(f"{ilan_toplam_row:,.0f}" if ilan_ucret else "", 3, y, size=6.5, align="right")
        _tbl_cell(f"{ogr_ucret:,.0f}" if ogr_ucret else "", 4, y, size=6.5, align="right")
        _tbl_cell(f"%{_kdv_oran:.0f}" if ogr_ucret else "", 5, y, size=6, align="center", color=GRAY_TEXT)
        _tbl_cell(f"{ogr_toplam_row:,.0f}" if ogr_ucret else "", 6, y, size=6.5, align="right")
        _tbl_hline(y - 0.2 * cm)
        y -= _row_h

