    _odeme_sekli = sozlesme.get("odeme_sekli", "")
    _pesin_check = "(X)" if _odeme_sekli == "Peşin" else "(   )"
    _taksit_check = "(X)" if _odeme_sekli == "Taksit" else "(   )"
    _odeme_row("Ödeme Şekli", f"{_pesin_check} Peşin          {_taksit_check} Taksit", _orow); _orow += 1

