    def _section_header(title: str):
        nonlocal y
        _check(2.5 * cm)
        y -= 0.35 * cm
        # Sol accent bar (NAVY)
        c.setFillColorRGB(*NAVY)
        c.rect(margin_l, y - 0.45 * cm, 4 * mm, 0.65 * cm, fill=True, stroke=False)
        # Arka plan (açık gri)
        c.setFillColorRGB(*LIGHT_BG)
        c.rect(margin_l + 4 * mm, y - 0.45 * cm, usable_w - 4 * mm, 0.65 * cm, fill=True, stroke=False)
        # Alt çizgi (GOLD accent)
        c.setStrokeColorRGB(*GOLD)
        c.setLineWidth(0.6)
        c.line(margin_l, y - 0.45 * cm, margin_l + usable_w, y - 0.45 * cm)
        # Başlık metni
        c.setFillColorRGB(*NAVY)
        c.setFont(font_bold, 9.5)
        c.drawString(margin_l + 7 * mm, y - 0.28 * cm, title)
        c.setFillColorRGB(*DARK_TEXT)
        y -= 1.15 * cm

    def _write_items(items: list[str], numbered: bool = True, size: float = 7.5, leading: float = 10):
        nonlocal y
        for i, item in enumerate(items, 1):
            _check(1.5 * cm)
            prefix = f"{i}. " if numbered else "• "
            # Numara/madde prefix bold, geri kalan normal
            c.setFillColorRGB(*DARK_TEXT)
            y = _draw_wrapped(f"{prefix}{item}", margin_l + 0.3 * cm, y, usable_w - 0.6 * cm, size=size, leading=leading)
            y -= 0.15 * cm

