def resolve_logo_path(profile: dict[str, Any]) -> str:
    raw = str(profile.get("logo_path") or "").strip()
    if not raw:
        return ""
    path = raw
    if not os.path.isabs(path):
        path = os.path.join(os.getcwd(), path)
    return path if os.path.exists(path) else ""


