def read_csv_with_fallback(path: str) -> pd.DataFrame:
    for enc in ("utf-8-sig", "cp1254", "latin-1"):
        try:
            return pd.read_csv(path, encoding=enc)
        except Exception:
            continue
    try:
        return pd.read_csv(path, encoding="utf-8", errors="ignore")
    except Exception:
        return pd.DataFrame()


def find_import_csv(filename: str) -> str:
    root = ".streamlit"
    if not os.path.isdir(root):
        return ""
    for base, _, files in os.walk(root):
        if filename in files:
            return os.path.join(base, filename)
    return ""


def load_import_csv(filename: str) -> pd.DataFrame:
    candidate = os.path.join(PR01_BASE, "02_Import", filename)
    if os.path.exists(candidate):
        return read_csv_with_fallback(candidate)
    fallback = find_import_csv(filename)
    if fallback:
        return read_csv_with_fallback(fallback)
    return pd.DataFrame()


# ==================== TEXT UTILS ====================


def normalize_text(value: Any) -> str:
    text = "" if value is None else str(value)
    normalized = unicodedata.normalize("NFKD", text)
    return "".join(char for char in normalized if not unicodedata.combining(char))


def _normalize_identifier(value: Any) -> str:
    return normalize_text(value).strip().lower()


def _normalized_lead_key(name_value: Any, student_value: Any) -> tuple[str, str]:
    return (
        _normalize_identifier(name_value),
        _normalize_identifier(student_value),
    )


def _build_lead_result_map(
    invites: list[dict[str, Any]]
) -> dict[tuple[str, str], str]:
    result_map: dict[tuple[str, str], str] = {}
    for invite in invites:
        latest = _latest_call_info(invite)
        if not latest:
            continue
        key = _normalized_lead_key(invite.get("Aday"), invite.get("Öğrenci"))
        if not any(key):
            continue
        result_map[key] = normalize_text(latest.get("result")).strip().lower()
    return result_map


def _leads_with_results(
    leads: list[dict[str, Any]],
    result_map: dict[tuple[str, str], str],
    allowed_results: set[str],
) -> list[dict[str, Any]]:
    matches: list[dict[str, Any]] = []
    for lead in leads:
        key = _normalized_lead_key(lead.get("name"), lead.get("student_name"))
        if not any(key):
            continue
        if result_map.get(key) in allowed_results:
            matches.append(lead)
    return matches


def _lead_call_state(
    lead: dict[str, Any],
    result_map: dict[tuple[str, str], str],
) -> tuple[str, str | None]:
    key = _normalized_lead_key(lead.get("name"), lead.get("student_name"))
    result = result_map.get(key)
    if not result:
        return "not_called", None
    display = normalize_status(result)
    normalized_key = display.lower()
    if normalized_key in NEGATIVE_CALL_RESULTS:
        return "negative", display
    return "called", display


def render_tts_player(text: str, *, key: str) -> None:
    if not text:
        return
    safe_text = json.dumps(text)
    html = f"""
    <div style="margin:8px 0; display:flex; gap:8px; align-items:center;">
      <button id="btn_{key}" style="padding:6px 10px; border-radius:8px; border:1px solid #111; background:#111; color:#fff; cursor:pointer;">
        Dinle (TTS)
      </button>
      <button id="stop_{key}" style="padding:6px 10px; border-radius:8px; border:1px solid #999; background:#0f172a; color:#e2e8f0; color:#111; cursor:pointer;">
        Durdur
      </button>
      <span style="color:#666; font-size:12px;">TTS tarayici uzerinden oynatilir.</span>
    </div>
    <script>
      (function() {{
        const btn = document.getElementById("btn_{key}");
        const stopBtn = document.getElementById("stop_{key}");
        if (btn) {{
          btn.onclick = () => {{
            if (!window.speechSynthesis) return;
            window.speechSynthesis.cancel();
            const utter = new SpeechSynthesisUtterance({safe_text});
            utter.lang = "en-US";
            window.speechSynthesis.speak(utter);
          }};
        }}
        if (stopBtn) {{
          stopBtn.onclick = () => {{
            if (!window.speechSynthesis) return;
            window.speechSynthesis.cancel();
          }};
        }}
      }})();
    </script>
    """
    components.html(html, height=70)


SEARCH_TRANSLATION = str.maketrans({0x0131: "i"})


def pdf_safe(value: Any) -> str:
    text = normalize_text(value)
    return text.encode("latin-1", errors="ignore").decode("latin-1")


def _wrap_pdf_text(pdf: FPDF, text: Any, width: float) -> list[str]:
    safe_text = pdf_safe(text)
    if not safe_text:
        return [""]
    words = safe_text.split()
    if not words:
        return [""]
    lines: list[str] = []
    line = ""
    for word in words:
        test = f"{line} {word}".strip()
        if pdf.get_string_width(test) <= width:
            line = test
            continue
        if line:
            lines.append(line)
        if pdf.get_string_width(word) <= width:
            line = word
            continue
        chunk = ""
        for ch in word:
            test_chunk = f"{chunk}{ch}"
            if pdf.get_string_width(test_chunk) <= width:
                chunk = test_chunk
            else:
                if chunk:
                    lines.append(chunk)
                chunk = ch
        line = chunk
    if line:
        lines.append(line)
    return lines


def _fill_template(template: str, context: dict[str, Any]) -> str:
    try:
        return template.format(**context)
    except Exception:
        return template


