def _render_pdf_table(
    pdf: FPDF,
    rows: list[dict[str, Any]],
    headers: list[str] | None = None,
    col_widths: list[float] | None = None,
) -> None:
    if not rows:
        return
    if headers is None:
        headers = list(rows[0].keys())
    usable_width = pdf.w - pdf.l_margin - pdf.r_margin
    if col_widths is None:
        header_count = max(len(headers), 1)
        if header_count == 1:
            col_widths = [usable_width]
        else:
            weights: list[float] = []
            for header in headers:
                cells = [str(header or "")]
                cells += [str(row.get(header, "") or "") for row in rows]
                max_len = max(len(cell) for cell in cells)
                weights.append(max(max_len, 1))
            total_weight = sum(weights) or header_count
            col_widths = [max(usable_width * (weight / total_weight), usable_width * 0.1) for weight in weights]
            total = sum(col_widths)
            if total > usable_width:
                col_widths = [width * usable_width / total for width in col_widths]
    line_height = 6

    def render_header() -> None:
        pdf.set_fill_color(*PDF_TABLE_HEADER_FILL)
        pdf.set_text_color(*PDF_TABLE_TEXT)
        pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
        header_lines_list: list[list[str]] = []
        header_max_lines = 0
        for header, width in zip(headers, col_widths):
            header_lines = _wrap_pdf_text(pdf, header, width)
            header_lines_list.append(header_lines)
            header_max_lines = max(header_max_lines, max(len(header_lines), 1))
        header_height = header_max_lines * line_height
        x = pdf.l_margin
        y = pdf.get_y()
        for header_lines, width in zip(header_lines_list, col_widths):
            pdf.rect(x, y, width, header_height, style="DF")
            pdf.set_xy(x + 1, y + 1)
            for line in header_lines:
                pdf.cell(width - 2, line_height, line, border=0, fill=True, ln=1)
                pdf.set_x(x + 1)
            x += width
        pdf.set_xy(pdf.l_margin, y + header_height)
        pdf.ln(2)
        pdf.set_text_color(0, 0, 0)
        pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)

    render_header()
    for row in rows:
        cell_lines: list[list[str]] = []
        max_lines = 1
        for header, width in zip(headers, col_widths):
            lines = _wrap_pdf_text(pdf, row.get(header, ""), width)
            cell_lines.append(lines)
            max_lines = max(max_lines, len(lines))
        row_height = line_height * max_lines
        if pdf.get_y() + row_height > pdf.h - pdf.b_margin:
            pdf.add_page()
            render_header()
        y = pdf.get_y()
        x = pdf.l_margin
        for lines, width in zip(cell_lines, col_widths):
            pdf.rect(x, y, width, row_height)
            pdf.set_xy(x, y)
            for line in lines:
                pdf.cell(width, line_height, line, border=0, ln=1)
                pdf.set_x(x)
            x += width
            pdf.set_xy(x, y)
        pdf.set_y(y + row_height)


def normalize_status(value: Any) -> str:
    if value is None:
        return "Aday"
    raw = normalize_text(value).strip()
    if not raw:
        return "Aday"
    low = raw.lower()
    if low in {"lead", "aday"}:
        return "Aday"
    if low in {"olumsuz sonuc", "olumsuz sonuclandi", "kayit olumsuz sonuclandi"}:
        return "Olumsuz Sonuc"
    if low == "kayit sureci devam ediyor":
        return "On Kayıt"
    if low in {"kayit oldu", "kesin kayit", "kesin kayıt"}:
        return "Kayıt oldu"
    if low in {"kayit iptal", "kayıt iptal", "kayit iptali"}:
        return "Kayıt iptal"
    if low in {"kayit olumsuz", "kayit olumsuz sonuc"}:
        return "Kayıt olumsuz"
    return raw


