def _lead_name_label(lead: dict[str, Any]) -> str:
    return f"{lead.get('name','')} - {lead.get('student_name','')}"


def _tracking_history_key(label: str) -> str:
    return tenant_key(label)


def _tracking_history() -> dict[str, list[dict[str, Any]]]:
    # Her zaman dosyadan taze veri yükle - cache sorunu önlenir
    st.session_state["lead_tracking_history"] = load_tracking_history()
    return st.session_state["lead_tracking_history"]


def _tracking_history_for_label(label: str) -> list[dict[str, Any]]:
    return _tracking_history().get(_tracking_history_key(label), [])


def _append_tracking_entry(label: str, entry: dict[str, Any]) -> None:
    history = _tracking_history()
    key = _tracking_history_key(label)
    history.setdefault(key, []).append(entry)
    save_tracking_history(history)


def _lead_followup_result(lead: dict[str, Any]) -> str:
    label = _lead_name_label(lead)
    history = _tracking_history_for_label(label)
    if history:
        return normalize_followup_result(history[-1].get("result"))
    return normalize_followup_result(
        st.session_state.get(
            f"lead_tracking_{_tracking_history_key(label)}_followup_result", ""
        )
    )


def parse_channel_tokens(value: Any) -> list[str]:
    if value is None:
        return []
    return [token.strip() for token in str(value).split(",") if token.strip()]


def parse_months(value: Any) -> list[str]:
    if not value:
        return []
    cleaned = normalize_text(value).lower()
    for sep in ["-", "â", "â", "/", "|", ",", ";", " "]:
        cleaned = cleaned.replace(sep, " ")
    months = []
    for month in MONTHS_TR:
        if month.lower() in cleaned:
            months.append(month)
    return list(dict.fromkeys(months))


def trigger_rerun() -> None:
    st.rerun()


def schedule_auto_rerun(interval_ms: int = 1000) -> None:
    try:
        components.html(
            f"""
            <script>
            setTimeout(function() {{
                window.parent.postMessage({{type: 'streamlit:rerun'}}, '*');
            }}, {int(interval_ms)});
            </script>
            """,
            height=0,
        )
    except Exception:
        return


def _parse_iso_date(value: Any) -> datetime.date | None:
    if not value:
        return None
    try:
        return datetime.fromisoformat(str(value)).date()
    except ValueError:
        return None


def _campaign_identifier(row: dict[str, Any], fallback: str) -> str:
    code = str(row.get("Kod") or "").strip()
    if code:
        return code
    name = str(row.get("KampanyaAdi") or "").strip()
    if name:
        return name
    return fallback


