def load_leads(filter_by_year: bool = True) -> list[dict[str, Any]]:
    raw = load_json_list(get_pr01_leads_path())
    cleaned = []

    # Seçili eğitim yılını al
    selected_year = st.session_state.get("current_egitim_yili", "2025-2026") if filter_by_year else None

    for lead in raw:
        name = str(lead.get("name", "")).strip()
        if name.lower() in BANNED_SAMPLE_LEAD_NAMES:
            continue
        entry = dict(lead)
        entry["status"] = normalize_status(entry.get("status"))
        if entry["status"] not in LEAD_STATUS_LABELS:
            entry["status"] = "Aday"

        # Eğitim yılı filtresi uygula
        if filter_by_year and selected_year:
            lead_year = entry.get("egitim_yili", "2025-2026")
            if lead_year != selected_year:
                continue

        cleaned.append(entry)
    return cleaned


