def save_candidate_test_result(
    candidate_label: str,
    test_name: str,
    test_file: str,
    source: str = "davet_uygulama_testleri"
) -> None:
    """
    Adaya uygulanan testi kaydeder - hem gorusme sonuclarina hem takip gecmisine isler.

    Args:
        candidate_label: "Veli Adı - Öğrenci Adı" formati
        test_name: Test adi (ornek: "Coklu Zeka Testi")
        test_file: Test dosya key'i (ornek: "EXAM_VARK_7_9")
        source: Testin yapildigi ekran ("gorusme" veya "davet_uygulama_testleri")
    """
    meeting_results = load_meeting_results()

    # Bu aday için mevcut kaydi bul veya yeni olustur
    existing_record = None
    for mr in meeting_results:
        if mr.get("candidate", "").lower() == candidate_label.lower():
            existing_record = mr
            break

    if existing_record:
        # Mevcut testlere ekle
        current_tests = existing_record.get("DavetTestleriSecimler", "")
        test_list = [t.strip() for t in current_tests.split(";") if t.strip()] if current_tests else []
        if test_name not in test_list:
            test_list.append(test_name)
        existing_record["DavetTestleriSecimler"] = "; ".join(test_list)
        existing_record["son_test_tarihi"] = datetime.now().isoformat()
        existing_record["son_test_adi"] = test_name
        existing_record["son_test_kaynak"] = source
    else:
        # Yeni kayit olustur
        parts = candidate_label.split(" - ")
        veli_adi = parts[0] if parts else ""
        ogrenci_adi = parts[1] if len(parts) > 1 else ""

        new_record = {
            "candidate": candidate_label,
            "Aday": veli_adi,
            "Öğrenci": ogrenci_adi,
            "result": "Test uygulandi",
            "notes": f"{test_name} testi uygulandi",
            "flags": [],
            "mode": "Test",
            "meeting_order": "-",
            "saved_at": datetime.now().isoformat(),
            "DavetTestleriSecimler": test_name,
            "son_test_tarihi": datetime.now().isoformat(),
            "son_test_adi": test_name,
            "son_test_kaynak": source,
        }
        meeting_results.append(new_record)

    save_meeting_results(meeting_results)

    # Aktivite loguna ekle
    append_activity_log(
        "Test uygulandi",
        source,
        details=f"{candidate_label} - {test_name}",
    )


def load_followup_rules() -> dict[str, int | None]:
    data = load_json_dict(get_pr01_followup_rules_path())
    rules: dict[str, int | None] = dict(DEFAULT_FOLLOWUP_RULES)
    if isinstance(data, dict):
        for key, value in data.items():
            if value is None:
                rules[key] = None
            else:
                try:
                    rules[key] = int(value)
                except (TypeError, ValueError):
                    continue
    return rules


