def _build_manual_month_plan(
    alt_defaults: list[str],
    year: int,
) -> dict[str, dict[str, Any]]:
    """Aylık kampanya planı oluşturur.

    - available_campaigns: Kampanya havuzu (tüm seçenekler)
    - selected_campaigns: Kullanıcının seçip detaylarını girdiği aktif kampanyalar (başlangıçta boş)
    """
    alt_list = alt_defaults or [
        "Google Search (Arama Agi)",
        "Meta: Instagram Feed/Story/Reels",
        "Web sitesi (landing page) + SEO",
        "WhatsApp Business (yayin listesi/katalog)",
        "Google Maps / Yerel Arama (GBP)",
    ]
    base_mecra = ", ".join(DEFAULT_MAIN_MECRAS)
    plans: dict[str, dict[str, Any]] = {}
    for month_name in MONTHS_TR:
        if month_name == "Ocak":
            items = list(JANUARY_ITEMS)
        else:
            items = list(CORE_MONTH_ITEMS)
            items.extend(MONTHLY_EXTRA_ITEMS.get(month_name, []))
            items = _limit_burs_items(month_name, items)
        # Tekrar eden kampanyaları temizle (sırayı koruyarak)
        seen = set()
        unique_items = []
        for item in items:
            if item not in seen:
                seen.add(item)
                unique_items.append(item)
        items = unique_items
        # Kampanyaları öncelik sırasına göre sırala
        items = _sirala_kampanyalar(items)

        # Kampanya havuzu (tüm seçenekler)
        start_date, end_date = _month_date_range(year, month_name)
        available: list[dict[str, Any]] = []
        for idx, item in enumerate(items, start=1):
            available.append({
                "id": f"POOL_{month_name}_{idx}",
                "Kod": f"POOL-{month_name[:3].upper()}-{idx:02d}",
                "KampanyaAdi": item,
                "amac": _purpose_for_item(item),
                "varsayilan_mecra": base_mecra,
                "varsayilan_alt_mecralar": list(alt_list),
                "varsayilan_baslangic": start_date,
                "varsayilan_bitis": end_date,
            })

        plans[month_name] = {
            "available_campaigns": available,  # Kampanya havuzu
            "selected_campaigns": {},  # Kullanıcının seçtikleri (başlangıçta boş)
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
    return plans


def _build_auto_plan(
    df_campaigns: pd.DataFrame,
    alt_defaults: list[str],
    year: int,
) -> dict[str, dict[str, Any]]:
    return _build_manual_month_plan(alt_defaults, year)


def _parse_date_string(value: Any) -> datetime.date | None:
    if not value:
        return None
    try:
        return datetime.fromisoformat(str(value)).date()
    except ValueError:
        return None


def _latest_call_info(entry: dict[str, Any]) -> dict[str, Any] | None:
    for idx in range(5, 0, -1):
        suffix = "" if idx == 1 else str(idx)
        result = entry.get(f"{suffix}Sonuc")
        call_date = _parse_date_string(entry.get(f"{suffix}Tarih"))
        if not result or not call_date:
            continue
        return {
            "idx": idx,
            "result": result,
            "date": call_date,
            "time": entry.get(f"{suffix}Saat", ""),
            "caller": entry.get(f"{suffix}Arayan", ""),
            "caller_role": entry.get(f"{suffix}ArayanGörev", ""),
            "note": entry.get(f"{suffix}Not", ""),
            "other_note": entry.get(f"{suffix}DigerNot", ""),
        }
    return None


def _previous_call_info(entry: dict[str, Any], before_idx: int) -> dict[str, Any] | None:
    for idx in range(before_idx - 1, 0, -1):
        suffix = "" if idx == 1 else str(idx)
        result = entry.get(f"{suffix}Sonuc")
        call_date = _parse_date_string(entry.get(f"{suffix}Tarih"))
        if not result or not call_date:
            continue
        return {
            "idx": idx,
            "result": result,
            "date": call_date,
            "time": entry.get(f"{suffix}Saat", ""),
            "caller": entry.get(f"{suffix}Arayan", ""),
            "caller_role": entry.get(f"{suffix}ArayanGörev", ""),
            "note": entry.get(f"{suffix}Not", ""),
            "other_note": entry.get(f"{suffix}DigerNot", ""),
        }
    return None


def _build_reminders(
    invites: list[dict[str, Any]],
    followup_rules: dict[str, int | None],
) -> list[dict[str, Any]]:
    reminders: list[dict[str, Any]] = []
    for entry in invites:
        latest = _latest_call_info(entry)
        if not latest:
            continue
        if latest["result"] in NO_TRACK_RESULTS:
            continue
        followup_days = followup_rules.get(latest["result"], 1)
        if followup_days is None:
            continue
        reminder_date = latest["date"] + timedelta(days=followup_days)
        reminders.append(
            {
                "Aday": entry.get("Aday", ""),
                "Öğrenci": entry.get("Öğrenci", ""),
                "Kampanya": entry.get("Kampanya", ""),
                "Mecra": entry.get("Mecra", ""),
                "Arama": f"Arama {latest['idx']}",
                "AramaTarihi": latest["date"].isoformat(),
                "HatirlatmaTarihi": reminder_date.isoformat(),
                "TakipGünü": followup_days,
                "AramaSonucu": latest["result"],
                "Arayan": latest["caller"],
                "ArayanGörev": latest["caller_role"],
                "Not": latest["note"],
                "DigerNot": latest["other_note"],
                "Telefon": entry.get("Telefon", ""),
                "E-posta": entry.get("E-posta", ""),
            }
        )
    reminders.sort(key=lambda row: row.get("HatirlatmaTarihi", ""), reverse=True)
    return reminders


def _build_call_result_report(invites: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for entry in invites:
        latest = _latest_call_info(entry)
        if not latest:
            continue
        rows.append(
            {
                "Aday": entry.get("Aday", ""),
                "Öğrenci": entry.get("Öğrenci", ""),
                "Kampanya": entry.get("Kampanya", ""),
                "Mecra": entry.get("Mecra", ""),
                "Son Arama": f"Arama {latest['idx']}",
                "Son Arama Tarihi": latest["date"].isoformat(),
                "Son Arama Saati": latest["time"],
                "Sonuc": latest["result"],
                "Not": latest["note"],
                "DigerNot": latest["other_note"],
                "Telefon": entry.get("Telefon", ""),
                "E-posta": entry.get("E-posta", ""),
            }
        )
    rows.sort(key=lambda row: row.get("Son Arama Tarihi", ""), reverse=True)
    return rows


def _build_update_report(invites: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for entry in invites:
        latest = _latest_call_info(entry)
        if not latest:
            continue
        previous = _previous_call_info(entry, latest["idx"])
        if not previous:
            continue
        if previous["result"] == latest["result"]:
            continue
        rows.append(
            {
                "Aday": entry.get("Aday", ""),
                "Öğrenci": entry.get("Öğrenci", ""),
                "Kampanya": entry.get("Kampanya", ""),
                "Mecra": entry.get("Mecra", ""),
                "Önceki Arama": f"Arama {previous['idx']}",
                "Önceki Sonuc": previous["result"],
                "Son Arama": f"Arama {latest['idx']}",
                "Sonuc": latest["result"],
                "Son Arama Tarihi": latest["date"].isoformat(),
                "Son Arama Saati": latest["time"],
                "Telefon": entry.get("Telefon", ""),
                "E-posta": entry.get("E-posta", ""),
                "Not": latest["note"],
                "DigerNot": latest["other_note"],
            }
        )
    rows.sort(key=lambda row: row.get("Son Arama Tarihi", ""), reverse=True)
    return rows


def _filter_reminders_by_date(
    reminders: list[dict[str, Any]],
    start_date: datetime.date,
    end_date: datetime.date,
) -> list[dict[str, Any]]:
    filtered: list[dict[str, Any]] = []
    for row in reminders:
        row_date = _parse_date_string(row.get("HatirlatmaTarihi"))
        if not row_date:
            continue
        if start_date <= row_date <= end_date:
            filtered.append(row)
    return filtered


def _filter_rows_by_date_key(
    rows: list[dict[str, Any]],
    date_key: str,
    start_date: datetime.date,
    end_date: datetime.date,
) -> list[dict[str, Any]]:
    filtered: list[dict[str, Any]] = []
    for row in rows:
        row_date = _parse_date_string(row.get(date_key))
        if not row_date:
            continue
        if start_date <= row_date <= end_date:
            filtered.append(row)
    return filtered


def _merge_note(base: str, extra: str) -> str:
    base = (base or "").strip()
    extra = (extra or "").strip()
    if not extra:
        return base
    return f"{base}\n{extra}" if base else extra


def _collect_needs_labels(
    invites: list[dict[str, Any]],
    meetings: list[dict[str, Any]],
    lead: dict[str, Any],
    meeting_results: list[dict[str, Any]] | None = None,
) -> list[str]:
    labels: list[str] = []
    for invite in invites:
        if invite.get("Aday") != lead.get("name"):
            continue
        if invite.get("Öğrenci") != lead.get("student_name"):
            continue
        for key, value in invite.items():
            if not key.endswith("AramaDestekNotları"):
                continue
            raw = str(value or "").strip()
            if not raw:
                continue
            parts = [part.strip() for part in raw.split(";") if part.strip()]
            labels.extend(parts)
    for meeting in meetings:
        if meeting.get("Aday") != lead.get("name"):
            continue
        if meeting.get("Öğrenci") != lead.get("student_name"):
            continue
        raw = str(meeting.get("YuzYuzeIhtiyacSecimler") or "").strip()
        if raw:
            parts = [part.strip() for part in raw.split(";") if part.strip()]
            labels.extend(parts)
    # Görüşme sonuçlarından da İhtiyaç Analizi verilerini topla
    if meeting_results:
        for result in meeting_results:
            # candidate formatı: "Veli Adı - Öğrenci Adı"
            if result.get("Aday") != lead.get("name"):
                continue
            if result.get("Öğrenci") != lead.get("student_name"):
                continue
            raw = str(result.get("YuzYuzeIhtiyacSecimler") or "").strip()
            if raw:
                parts = [part.strip() for part in raw.split(";") if part.strip()]
                labels.extend(parts)
    return labels


def _needs_category_counts(labels: list[str]) -> Counter:
    counts = Counter()
    for label in labels:
        category = NEEDS_CATEGORY_MAP.get(label, "Diger")
        counts[category] += 1
    return counts


def _collect_parent_question_labels(
    meetings: list[dict[str, Any]],
    lead: dict[str, Any],
) -> list[str]:
    labels: list[str] = []
    for meeting in meetings:
        if meeting.get("Aday") != lead.get("name"):
            continue
        if meeting.get("Öğrenci") != lead.get("student_name"):
            continue
        raw = str(meeting.get("VeliSoruCevapSecimler") or "").strip()
        if not raw:
            continue
        parts = [part.strip() for part in raw.split(";") if part.strip()]
        labels.extend(parts)
    return labels


def _split_selection_labels(raw: str) -> list[str]:
    stripped = str(raw or "")
    if not stripped.strip():
        return []
    return [part.strip() for part in stripped.split(";") if part.strip()]


def _collect_label_counts(
    meetings: list[dict[str, Any]],
    lead: dict[str, Any],
    field_name: str,
    meeting_results: list[dict[str, Any]] | None = None,
) -> Counter:
    counts: Counter = Counter()
    for meeting in meetings:
        if meeting.get("Aday") != lead.get("name"):
            continue
        if meeting.get("Öğrenci") != lead.get("student_name"):
            continue
        raw = meeting.get(field_name, "")
        for label in _split_selection_labels(raw):
            counts[label] += 1
    # Görüşme sonuçlarından da veri topla
    if meeting_results:
        for result in meeting_results:
            if result.get("Aday") != lead.get("name"):
                continue
            if result.get("Öğrenci") != lead.get("student_name"):
                continue
            raw = result.get(field_name, "")
            for label in _split_selection_labels(raw):
                counts[label] += 1
    return counts


def _collect_flow_label_counts(
    meetings: list[dict[str, Any]],
    lead: dict[str, Any],
    meeting_results: list[dict[str, Any]] | None = None,
) -> Counter:
    return _collect_label_counts(meetings, lead, "YuzYuzeAkisSecimler", meeting_results)


def _collect_needs_selection_counts(
    meetings: list[dict[str, Any]],
    lead: dict[str, Any],
    meeting_results: list[dict[str, Any]] | None = None,
) -> Counter:
    return _collect_label_counts(meetings, lead, "YuzYuzeIhtiyacSecimler", meeting_results)


def _aggregate_meeting_needs(
    meetings: list[dict[str, Any]],
    meeting_results: list[dict[str, Any]] | None = None,
) -> tuple[Counter, Counter]:
    category_counts: Counter = Counter()
    selection_counts: Counter = Counter()
    for meeting in meetings:
        raw = str(meeting.get("YuzYuzeIhtiyacSecimler") or "").strip()
        if not raw:
            continue
        for label in _split_selection_labels(raw):
            selection_counts[label] += 1
            category = NEEDS_CATEGORY_MAP.get(label, "Diger")
            category_counts[category] += 1
    # Görüşme sonuçlarından da İhtiyaç Analizi verilerini topla
    if meeting_results:
        for result in meeting_results:
            raw = str(result.get("YuzYuzeIhtiyacSecimler") or "").strip()
            if not raw:
                continue
            for label in _split_selection_labels(raw):
                selection_counts[label] += 1
                category = NEEDS_CATEGORY_MAP.get(label, "Diger")
                category_counts[category] += 1
    return category_counts, selection_counts


def _filter_leads_by_date(
    leads: list[dict[str, Any]], start: date, end: date
) -> list[dict[str, Any]]:
    filtered: list[dict[str, Any]] = []
    for lead in leads:
        created = _parse_iso_datetime(lead.get("created_date") or lead.get("created_at"))
        if not created:
            continue
        if start <= created.date() <= end:
            filtered.append(lead)
    return filtered


def _campaign_channel_summary(leads: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], Counter]:
    counter: Counter = Counter()
    for lead in leads:
        campaign = str(lead.get("campaign") or "(Belirtilmedi)").strip()
        channel = str(lead.get("channel") or "(Belirtilmedi)").strip()
        counter[(campaign, channel)] += 1
    rows = [
        {"Kampanya": camp, "Mecra": chan, "Aday": count}
        for (camp, chan), count in sorted(counter.items(), key=lambda item: (-item[1], item[0]))
    ]
    pie_counts: Counter = Counter()
    for (camp, chan), count in counter.items():
        label = f"{camp} / {chan}"
        pie_counts[label] = count
    return rows, pie_counts


def _school_type_summary(leads: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], Counter]:
    counter: Counter = Counter()
    for lead in leads:
        school_type = str(lead.get("school_type") or "(Belirtilmedi)").strip()
        counter[school_type] += 1
    rows = [
        {"Okul Turu": school_type, "Aday": count}
        for school_type, count in sorted(counter.items(), key=lambda item: (-item[1], item[0]))
    ]
    return rows, counter


def _grade_summary(leads: list[dict[str, Any]]) -> list[dict[str, Any]]:
    counter: Counter = Counter()
    for lead in leads:
        kademe = str(lead.get("kademe") or "(Belirtilmedi)").strip()
        grade = str(lead.get("current_grade") or "").strip()
        if grade:
            label = f"{kademe} - {grade}"
        else:
            label = kademe
        counter[label] += 1
    return [
        {"Kademe / Sınıf": label, "Aday": count}
        for label, count in sorted(counter.items(), key=lambda item: (-item[1], item[0]))
    ]


def _meetings_for_lead(
    meetings: list[dict[str, Any]],
    lead: dict[str, Any],
) -> list[dict[str, Any]]:
    filtered = [
        meeting
        for meeting in meetings
        if meeting.get("Aday") == lead.get("name")
        and meeting.get("Öğrenci") == lead.get("student_name")
    ]
    return sorted(
        filtered,
        key=lambda m: (
            str(m.get("Tarih") or ""),
            str(m.get("Saat") or ""),
        ),
    )


def _format_candidate_report_text(report_rows: list[dict[str, Any]]) -> str:
    lines: list[str] = []
    current_section: str | None = None
    for row in report_rows:
        section = row.get("Bolum", "")
        if section != current_section:
            if current_section is not None:
                lines.append("")
            lines.append(f"=== {section} ===")
            current_section = section
        lines.append(f"{row.get('Alan', '')}: {row.get('Deger', '')}")
    return "\n".join(lines).strip()


def _text_to_pdf_bytes(text: str) -> bytes:
    if FPDF is None:
        return text.encode("utf-8")
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.add_page()
    pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
    for line in text.splitlines():
        pdf.multi_cell(0, 6, line)
    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def _generate_candidate_report_package(
    lead: dict[str, Any],
    invites: list[dict[str, Any]],
    meetings: list[dict[str, Any]],
    meeting_results: list[dict[str, Any]] | None = None,
) -> tuple[bytes | None, str | None]:
    meeting_rows = [
        meeting
        for meeting in meetings
        if meeting.get("Aday") == lead.get("name")
        and meeting.get("Öğrenci") == lead.get("student_name")
    ]
    needs_labels = _collect_needs_labels(invites, meeting_rows, lead, meeting_results)
    needs_counts = _needs_category_counts(needs_labels)
    needs_selection_counts = _collect_needs_selection_counts(meeting_rows, lead, meeting_results)
    flow_label_counts = _collect_flow_label_counts(meeting_rows, lead, meeting_results)
    pdf_bytes: bytes | None = None
    error: str | None = None
    try:
        pdf_bytes = generate_candidate_pdf(
            lead,
            invites,
            meeting_rows,
            needs_counts,
            needs_selection_counts,
            flow_label_counts,
            meeting_results,
        )
    except Exception as exc:  # pragma: no cover
        error = str(exc)
    if not pdf_bytes:
        fallback_text = _format_candidate_report_text(
            _build_candidate_report_rows(lead, invites, meeting_rows, meeting_results)
        )
        fallback_text = fallback_text or "Rapor verisi bulunamadı."
        pdf_bytes = _text_to_pdf_bytes(fallback_text)
    return pdf_bytes, error


def _build_candidate_report_rows(
    lead: dict[str, Any],
    invites: list[dict[str, Any]],
    meetings: list[dict[str, Any]],
    meeting_results: list[dict[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []

    def add_row(section: str, field: str, value: Any) -> None:
        if value is None:
            return
        value_str = str(value).strip()
        if not value_str:
            return
        rows.append({"Bolum": section, "Alan": field, "Deger": value_str})

    report_date = datetime.now().strftime("%Y-%m-%d %H:%M")
    add_row("Rapor", "Rapor Tarihi", report_date)

    meeting_rows = [
        meeting
        for meeting in meetings
        if meeting.get("Aday") == lead.get("name")
        and meeting.get("Öğrenci") == lead.get("student_name")
    ]
    if meeting_rows:
        latest_meeting = max(
            meeting_rows,
            key=lambda m: (
                str(m.get("Tarih") or ""),
                str(m.get("Saat") or ""),
            ),
        )
        add_row("Rapor", "Toplam Görüşme", len(meeting_rows))
        add_row("Rapor", "Son Görüşme Tarihi", latest_meeting.get("Tarih", ""))
        add_row("Rapor", "Son Görüşme Saati", latest_meeting.get("Saat", ""))
        add_row("Rapor", "Son Görüşme Sonucu", latest_meeting.get("Sonuc", ""))

    # Öğrenci bilgileri önce
    add_row("Öğrenci Bilgileri", "Öğrenci Adi", lead.get("student_name", ""))
    add_row("Öğrenci Bilgileri", "Cinsiyet", lead.get("gender", ""))
    add_row("Öğrenci Bilgileri", "Kademe", lead.get("kademe", ""))
    add_row("Öğrenci Bilgileri", "Su anki sinif", lead.get("current_grade", ""))
    add_row("Öğrenci Bilgileri", "Istedigi sinif", lead.get("desired_grade", ""))
    add_row("Öğrenci Bilgileri", "Geldigi okul turu", lead.get("school_type", ""))
    add_row("Öğrenci Bilgileri", "Geldigi okul adi", lead.get("school_name", ""))
    add_row("Öğrenci Bilgileri", "Durum", lead.get("status", ""))

    # Veli bilgileri
    add_row("Veli Bilgileri", "Veli Adi Soyadi", lead.get("name", ""))
    add_row("Veli Bilgileri", "Telefon", lead.get("phone", ""))
    add_row("Veli Bilgileri", "E-posta", lead.get("email", ""))
    add_row("Veli Bilgileri", "Öncelikler", lead.get("Öncelikler", lead.get("oncelikler", "")))
    add_row("Veli Bilgileri", "Kayıt tarihi", lead.get("created_date", ""))
    add_row("Veli Bilgileri", "Kayıt saati", lead.get("created_time", ""))

    add_row("Kampanya", "Kampanya", lead.get("campaign", ""))
    add_row("Kampanya", "Mecra", lead.get("channel", ""))
    add_row("Kampanya", "Kaynak Notu", lead.get("source", ""))

    # Sözleşme bilgileri
    ogrenci_label = f"{lead.get('name', '')} - {lead.get('student_name', '')}"
    sozlesme = get_sozlesme_by_ogrenci(ogrenci_label)
    if sozlesme:
        add_row("Sozlesme Bilgileri", "Sozlesme Tarihi", sozlesme.get("sozlesme_tarihi", ""))
        add_row("Sozlesme Bilgileri", "Kayıt Durumu", sozlesme.get("kayit_durumu", ""))
        add_row("Sozlesme Bilgileri", "Odeme Tipi", sozlesme.get("odeme_tipi", ""))
        add_row("Sozlesme Bilgileri", "Eğitim Ücreti", f"₺{sozlesme.get('egitim_ucreti', 0):,.0f}")
        add_row("Sozlesme Bilgileri", "Ek Hizmet Ücreti", f"₺{sozlesme.get('ek_hizmet_ucreti', 0):,.0f}")
        add_row("Sozlesme Bilgileri", "Toplam Ücret", f"₺{sozlesme.get('toplam_ucret', 0):,.0f}")
        add_row("Sozlesme Bilgileri", "Pesinat", f"₺{sozlesme.get('pesinat', 0):,.0f}")
        add_row("Sozlesme Bilgileri", "Kalan Borc", f"₺{sozlesme.get('kalan_borc', 0):,.0f}")
        add_row("Sozlesme Bilgileri", "Taksit Sayısı", sozlesme.get("taksit_sayisi", ""))
        add_row("Sozlesme Bilgileri", "Aylık Taksit", f"₺{sozlesme.get('aylik_taksit', 0):,.0f}")
        add_row("Sozlesme Bilgileri", "Indirim Orani", f"%{sozlesme.get('indirim_orani', 0)}")
        add_row("Sozlesme Bilgileri", "Indirim Turu", sozlesme.get("indirim_turu", ""))
        add_row("Sozlesme Bilgileri", "Notlar", sozlesme.get("notlar", ""))

    # Tracking history (arama geçmişi)
    tracking_history = load_tracking_history()
    lead_key = _tracking_history_key(ogrenci_label)
    lead_history = tracking_history.get(lead_key, [])
    if lead_history:
        for idx, entry in enumerate(sorted(lead_history, key=lambda x: (x.get("date", ""), x.get("time", "")), reverse=True)[:10], 1):
            section = f"İşlem Geçmişi {idx}"
            add_row(section, "Tarih", entry.get("date", ""))
            add_row(section, "Saat", entry.get("time", ""))
            add_row(section, "İşlem", entry.get("action", ""))
            add_row(section, "Sonuc", entry.get("result", ""))
            add_row(section, "Yapan", entry.get("owner", ""))
            add_row(section, "Not", entry.get("note", ""))

    # Ihtiyac analizi (kategori sayim)
    labels = _collect_needs_labels(invites, meetings, lead, meeting_results)
    counts = Counter()
    for label in labels:
        category = NEEDS_CATEGORY_MAP.get(label, "Diger")
        counts[category] += 1
    if counts:
        for category, count in counts.items():
            add_row("Ihtiyac Analizi", category, count)

    needs_selection_counts = _collect_needs_selection_counts(meeting_rows, lead, meeting_results)
    if needs_selection_counts:
        for label, count in needs_selection_counts.items():
            add_row("Yuz Yuze Ihtiyac Secimleri", label, count)

    # Veli sorulari (toplam ve dagilim)
    parent_labels = _collect_parent_question_labels(meetings, lead)
    parent_counts = Counter(parent_labels)
    if parent_counts:
        add_row("Veli Sorulari", "Toplam Sorulan", sum(parent_counts.values()))
        for question, count in parent_counts.items():
            add_row("Veli Sorulari", question, count)

    # Veli goZlem notlari (sorulmayan konulara yazilan notlar)
    observation_notes = []
    for meeting in meeting_rows:
        raw_notes = str(meeting.get("VeliSoruCevapNotları") or "").strip()
        if not raw_notes:
            continue
        selected_questions = [
            part.strip()
            for part in str(meeting.get("VeliSoruCevapSecimler") or "").split(";")
            if part.strip()
        ]
        for line in raw_notes.splitlines():
            if not any(line.startswith(question) for question in selected_questions):
                observation_notes.append(
                    (
                        str(meeting.get("Tarih", "")).strip(),
                        str(meeting.get("Saat", "")).strip(),
                        line,
                    )
                )
    if observation_notes:
        for date_value, time_value, line in observation_notes:
            when = " ".join(part for part in [date_value, time_value] if part).strip()
            label = "Not"
            if when:
                label = f"Not ({when})"
            add_row("Veli Gozlem Notları", label, line)

    # Davet uygulama testleri
    for meeting in meeting_rows:
        add_row(
            "Davet Uygulama Testleri",
            "Secimler",
            meeting.get("DavetTestleriSecimler", ""),
        )

    # Fiyat gorusme akisi
    for meeting in meeting_rows:
        add_row("Fiyat Görüşme Akisi", "Secimler", meeting.get("FiyatAkisSecimler", ""))
        add_row("Fiyat Görüşme Akisi", "Notlar", meeting.get("FiyatAkisNotları", ""))
        add_row("Fiyat Görüşme Akisi", "Başlık Notları", meeting.get("FiyatAkisBaşlıkNotları", ""))
        add_row("Fiyat Kanaat", "Secimler", meeting.get("FiyatKanaatSecimler", ""))
        add_row("Fiyat Kanaat", "Notlar", meeting.get("FiyatKanaatNotları", ""))

    # Ozet notlar (baslik notlari toplu)
    for meeting in meeting_rows:
        add_row("Özet Notlar", "Yuz Yuze Akis Başlık Notları", meeting.get("YuzYuzeAkisBaşlıkNotları", ""))
        add_row("Özet Notlar", "Yuz Yuze Ihtiyac Başlık Notları", meeting.get("YuzYuzeIhtiyacBaşlıkNotları", ""))
        add_row("Özet Notlar", "Veli Soru-Cevap Başlık Notları", meeting.get("VeliSoruCevapBaşlıkNotları", ""))
        add_row("Özet Notlar", "Fiyat Akis Başlık Notları", meeting.get("FiyatAkisBaşlıkNotları", ""))

    # Fiyat hesaplayici ozeti
    for meeting in meeting_rows:
        add_row("Fiyat Hesaplayici", "Özet", meeting.get("FiyatHesapÖzeti", ""))
        add_row("Fiyat Hesaplayici", "Ek Hizmetler", meeting.get("FiyatHesapEkHizmetler", ""))
        add_row("Fiyat Hesaplayici", "Eğitim Hizmeti", meeting.get("FiyatHesapEgitim", ""))
        add_row("Fiyat Hesaplayici", "Toplam Fiyat", meeting.get("FiyatHesapToplam", ""))

    # Arama / Davet kayitlari
    for invite in invites:
        if invite.get("Aday") != lead.get("name"):
            continue
        if invite.get("Öğrenci") != lead.get("student_name"):
            continue
        latest_call = _latest_call_info(invite)
        if latest_call:
            add_row("Rapor", "Son Arama", f"Arama {latest_call.get('idx', '')}")
            add_row("Rapor", "Son Arama Tarihi", latest_call.get("date", ""))
            add_row("Rapor", "Son Arama Saati", latest_call.get("time", ""))
            add_row("Rapor", "Son Arama Sonucu", latest_call.get("result", ""))
        last_completed = 0
        appointment_idx = 0
        for idx in range(1, 6):
            suffix = "" if idx == 1 else str(idx)
            result_value = invite.get(f"{suffix}Sonuc", invite.get("Sonuc", ""))
            date_value = invite.get(f"{suffix}Tarih", invite.get("Tarih", ""))
            if result_value or date_value:
                last_completed = idx
            if result_value in APPOINTMENT_RESULTS and appointment_idx == 0:
                appointment_idx = idx

        max_idx = appointment_idx or last_completed
        if max_idx == 0:
            continue

        for idx in range(1, max_idx + 1):
            suffix = "" if idx == 1 else str(idx)
            section = f"Arama {idx}"
            add_row(section, "Tarih", invite.get(f"{suffix}Tarih", invite.get("Tarih", "")))
            add_row(section, "Saat", invite.get(f"{suffix}Saat", invite.get("Saat", "")))
            add_row(section, "Arayan", invite.get(f"{suffix}Arayan", invite.get("Arayan", "")))
            add_row(section, "Arayan Görev", invite.get(f"{suffix}ArayanGörev", invite.get("ArayanGörev", "")))
            add_row(section, "Sonuc", invite.get(f"{suffix}Sonuc", invite.get("Sonuc", "")))
            add_row(section, "Not", invite.get(f"{suffix}Not", invite.get("Not", "")))
            add_row(section, "Diger Not", invite.get(f"{suffix}DigerNot", invite.get("DigerNot", "")))
            add_row(section, "Arama Destek Notları", invite.get(f"{suffix}AramaDestekNotları", invite.get("AramaDestekNotları", "")))

    # Yuz yuze aday görüşme kayitlari
    if meeting_rows:
        for meeting in sorted(
            meeting_rows,
            key=lambda m: (
                str(m.get("Tarih") or ""),
                str(m.get("Saat") or ""),
            ),
        ):
            section = "Görüşme Kaydi"
            add_row(section, "Tarih", meeting.get("Tarih", ""))
            add_row(section, "Saat", meeting.get("Saat", ""))
            add_row(section, "Sonuc", meeting.get("Sonuc", ""))
            add_row(section, "Not", meeting.get("Not", ""))
            add_row(section, "Öncelikler", meeting.get("Öncelikler", ""))
            add_row(section, "Arama Destek Notları", meeting.get("AramaDestekNotları", ""))

        flow_counts = _collect_flow_label_counts(meeting_rows, lead, meeting_results)
        if flow_counts:
            for label, count in flow_counts.items():
                add_row("Yuz Yuze Gor Akis Secimleri", label, count)
            add_row(section, "Yuz Yuze Akis Secimleri", meeting.get("YuzYuzeAkisSecimler", ""))
            add_row(section, "Yuz Yuze Akis Notları", meeting.get("YuzYuzeAkisNotları", ""))
            add_row(section, "Yuz Yuze Akis Başlık Notları", meeting.get("YuzYuzeAkisBaşlıkNotları", ""))
            add_row(section, "Yuz Yuze Ihtiyac Secimleri", meeting.get("YuzYuzeIhtiyacSecimler", ""))
            add_row(section, "Yuz Yuze Ihtiyac Notları", meeting.get("YuzYuzeIhtiyacNotları", ""))
            add_row(section, "Yuz Yuze Ihtiyac Başlık Notları", meeting.get("YuzYuzeIhtiyacBaşlıkNotları", ""))
            add_row(section, "Veli Soru-Cevap Secimleri", meeting.get("VeliSoruCevapSecimler", ""))
            selected_questions = [
                part.strip()
                for part in str(meeting.get("VeliSoruCevapSecimler") or "").split(";")
                if part.strip()
            ]
            raw_notes = str(meeting.get("VeliSoruCevapNotları") or "").strip()
            kept = []
            other_notes = []
            if raw_notes:
                for line in raw_notes.splitlines():
                    matched = False
                    for question in selected_questions:
                        if line.startswith(question):
                            kept.append(line)
                            matched = True
                            break
                    if not matched:
                        other_notes.append(line)
            filtered_notes = "\n".join(kept).strip()
            observation_notes = "\n".join(other_notes).strip()
            add_row(section, "Veli Soru-Cevap Notları", filtered_notes)
            add_row(section, "Veli Gozlem Notları", observation_notes)
            add_row(section, "Veli Soru-Cevap Başlık Notları", meeting.get("VeliSoruCevapBaşlıkNotları", ""))
            add_row(section, "Davet Uygulama Testleri", meeting.get("DavetTestleriSecimler", ""))
            add_row(section, "Fiyat Akis Secimleri", meeting.get("FiyatAkisSecimler", ""))
            add_row(section, "Fiyat Akis Notları", meeting.get("FiyatAkisNotları", ""))
            add_row(section, "Fiyat Akis Başlık Notları", meeting.get("FiyatAkisBaşlıkNotları", ""))
            add_row(section, "Fiyat Kanaat Secimleri", meeting.get("FiyatKanaatSecimler", ""))
            add_row(section, "Fiyat Kanaat Notları", meeting.get("FiyatKanaatNotları", ""))
            add_row(section, "Fiyat Hesap Özeti", meeting.get("FiyatHesapÖzeti", ""))
            add_row(section, "Fiyat Ek Hizmetler", meeting.get("FiyatHesapEkHizmetler", ""))
            add_row(section, "Fiyat Eğitim Hizmeti", meeting.get("FiyatHesapEgitim", ""))
            add_row(section, "Fiyat Toplam", meeting.get("FiyatHesapToplam", ""))
            add_row(section, "Kampanya", meeting.get("Kampanya", ""))
            add_row(section, "Mecra", meeting.get("Mecra", ""))

    return rows


