def _get_zoom_sdk_credentials() -> tuple[str, str]:
    sdk_key = st.secrets.get("ZOOM_MEETING_SDK_KEY", "") if hasattr(st, "secrets") else ""
    sdk_secret = (
        st.secrets.get("ZOOM_MEETING_SDK_SECRET", "") if hasattr(st, "secrets") else ""
    )
    if not sdk_key:
        sdk_key = os.getenv("ZOOM_MEETING_SDK_KEY", "")
    if not sdk_secret:
        sdk_secret = os.getenv("ZOOM_MEETING_SDK_SECRET", "")
    return str(sdk_key).strip(), str(sdk_secret).strip()


def _base64url_encode(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b"=").decode("utf-8")


def _generate_zoom_signature(
    sdk_key: str,
    sdk_secret: str,
    meeting_number: str,
    role: int,
    expires_in: int = 60 * 60 * 2,
) -> str:
    now = int(time_module.time()) - 30
    exp = now + expires_in
    header = {"alg": "HS256", "typ": "JWT"}
    payload = {
        "sdkKey": sdk_key,
        "appKey": sdk_key,
        "mn": str(meeting_number),
        "role": int(role),
        "iat": now,
        "exp": exp,
        "tokenExp": exp,
    }
    header_b64 = _base64url_encode(json.dumps(header).encode("utf-8"))
    payload_b64 = _base64url_encode(json.dumps(payload).encode("utf-8"))
    message = f"{header_b64}.{payload_b64}".encode("utf-8")
    signature = hmac.new(sdk_secret.encode("utf-8"), message, hashlib.sha256).digest()
    signature_b64 = _base64url_encode(signature)
    return f"{header_b64}.{payload_b64}.{signature_b64}"


def _parse_zoom_link(link: str) -> tuple[str, str]:
    if not link:
        return "", ""
    meeting_number = ""
    passcode = ""
    match = re.search(r"/j/(\\d+)", link)
    if match:
        meeting_number = match.group(1)
    try:
        from urllib.parse import urlparse, parse_qs

        parsed = urlparse(link)
        params = parse_qs(parsed.query)
        if "pwd" in params and params["pwd"]:
            passcode = params["pwd"][0]
    except Exception:
        pass
    return meeting_number, passcode


def _subject_key(value: str) -> str:
    return normalize_text(value).lower()


@st.cache_data(show_spinner=False)
def _load_high_school_outcomes_catalog() -> pd.DataFrame:
    base = Path("data") / "tenants" / "aykin_koleji" / "imports" / "GEN-01"
    candidates = [
        "GEN-01_Lise9-12_TYT_perOutcome100.csv",
        "GEN-01_Lise9-12_AYT_perOutcome100.csv",
        "GEN-01_Lise9-12_DENEME_perOutcome100.csv",
        "GEN-01_Lise9-12_YAZILI_perOutcome100.csv",
    ]
    for name in candidates:
        path = base / name
        if path.exists():
            try:
                return pd.read_csv(
                    path,
                    usecols=["sinif_duzeyi", "brans", "kazanim_kodu", "kazanim_aciklama"],
                )
            except Exception:
                continue
    return pd.DataFrame()


def _high_school_outcomes_for(grade: int, subject: str) -> list[tuple[str, str]]:
    df = _load_high_school_outcomes_catalog()
    if df.empty:
        return []
    subject_key = _subject_key(subject)
    filtered = df[
        (df["sinif_duzeyi"].astype(str) == str(grade))
        & (df["brans"].astype(str).map(_subject_key) == subject_key)
    ]
    if filtered.empty:
        return []
    seen: set[tuple[str, str]] = set()
    outcomes: list[tuple[str, str]] = []
    for _, row in filtered.iterrows():
        code = str(row.get("kazanim_kodu", "")).strip()
        desc = str(row.get("kazanim_aciklama", "")).strip()
        key = (code, desc)
        if key in seen or not code:
            continue
        seen.add(key)
        outcomes.append(key)
    return outcomes


def _middle_school_outcome_for(subject: str, q_idx: int) -> tuple[str, str]:
    key = _subject_key(subject)
    mapping = {
        "turkce": [
            ("TR-ANL-01", "Sozcukte ve cumlede anlam"),
            ("TR-DIL-01", "Dil bilgisi kurallari"),
            ("TR-PAR-01", "Paragraf ve yazim kurallari"),
        ],
        "matematik": [
            ("MAT-SAY-01", "Sayılar ve islemler"),
            ("MAT-KES-01", "Kesirler ve oran-oranti"),
            ("MAT-GEO-01", "Olcu, geometri ve problemler"),
        ],
        "sosyal bilgiler": [
            ("SOS-COG-01", "Cografya ve yon bilgisi"),
            ("SOS-VAT-01", "Vatandaslik ve haklar"),
            ("SOS-KUL-01", "Kultur, toplum ve ekonomi"),
        ],
        "fen bilimleri": [
            ("FEN-MAD-01", "Madde ve isi"),
            ("FEN-CAN-01", "Canlilar ve yasam"),
            ("FEN-ENE-01", "Enerji ve elektrik"),
        ],
        "din kulturu": [
            ("DIN-DEV-01", "Degerler ve ahlak"),
            ("DIN-IBD-01", "Ibadet ve sorumluluk"),
        ],
        "ingilizce": [
            ("ENG-VOC-01", "Temel kelimeler"),
            ("ENG-GRA-01", "Temel dilbilgisi"),
        ],
        "inkilap tarihi ve ataturkculuk": [
            ("INK-TRH-01", "Milli mucadele ve inkilaplar"),
            ("INK-ILK-01", "Ataturk ilke ve inkilaplari"),
        ],
    }
    options = mapping.get(key)
    if not options:
        return ("GEN-001", "Genel kazanÄ±m")
    if key in {"din kulturu", "ingilizce"}:
        return options[0] if q_idx <= 3 else options[1]
    if q_idx <= 3:
        return options[0]
    if q_idx <= 6:
        return options[1]
    return options[-1]


def _build_need_distribution(subject_rows: list[dict[str, Any]]) -> tuple[list[str], list[float]]:
    buckets = {"Yuksek Ihtiyac": 0, "Orta Ihtiyac": 0, "Dusuk Ihtiyac": 0}
    for row in subject_rows:
        correct = float(row.get("Dogru", 0))
        wrong = float(row.get("Yanlis", 0))
        blank = float(row.get("Bos", 0))
        total = correct + wrong + blank
        acc = (correct / total) if total else 0
        if acc < 0.5:
            buckets["Yuksek Ihtiyac"] += 1
        elif acc < 0.7:
            buckets["Orta Ihtiyac"] += 1
        else:
            buckets["Dusuk Ihtiyac"] += 1
    labels = list(buckets.keys())
    values = [buckets[k] for k in labels]
    return labels, values


def _build_subject_recommendations(subject_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    recs = {
        "turk dili ve edebiyat": "Paragraf ve dil bilgisi için gunluk kisa okuma + 10 soru tekrar.",
        "matematik": "Temel kavram tekrar + gunluk 15 soru ve yanlis analizi.",
        "fizik": "Formul kartlari + problem cozumu ve grafik yorumlama.",
        "kimya": "Konu ozeti + tepkime turleri ve temel kavram tekrar.",
        "biyoloji": "Kavram haritasi + konu basligi bazli tekrar.",
        "sosyal bilgiler": "Kavram-okuma + harita ve yorum sorusu pratigi.",
        "inkilap tarihi ve ataturkculuk": "Kronoloji tablosu + kavram ve yorum sorulari.",
        "fen bilimleri": "Deney/olay-yorum sorulari ile tekrar.",
        "din kulturu": "Degerler ve kavram tekrar + kisa soru pratigi.",
        "ingilizce": "Temel kelime + kisa cumle ve dilbilgisi tekrar.",
    }
    rows: list[dict[str, Any]] = []
    for row in subject_rows:
        name = str(row.get("Ders", "")).strip()
        correct = float(row.get("Dogru", 0))
        wrong = float(row.get("Yanlis", 0))
        blank = float(row.get("Bos", 0))
        total = correct + wrong + blank
        acc = (correct / total) if total else 0
        if acc >= 0.7:
            continue
        key = _subject_key(name)
        rows.append(
            {
                "Ders": name,
                "Öncelik": "Yuksek" if acc < 0.5 else "Orta",
                "Oneri": recs.get(key, "Temel kavram tekrar + soru pratigi."),
            }
        )
    return rows


def _flatten_calls(invites: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for entry in invites:
        for idx in range(1, 6):
            suffix = "" if idx == 1 else str(idx)
            result_value = entry.get(f"{suffix}Sonuc", entry.get("Sonuc", ""))
            date_value = entry.get(f"{suffix}Tarih", entry.get("Tarih", ""))
            time_value = entry.get(f"{suffix}Saat", entry.get("Saat", ""))
            if not result_value and not date_value and not time_value:
                continue
            rows.append(
                {
                    "Tarih": str(date_value) if date_value else "",
                    "Saat": str(time_value) if time_value else "",
                    "AramaNo": idx,
                    "Sonuc": str(result_value) if result_value else "",
                    "Aday": entry.get("Aday", ""),
                    "Öğrenci": entry.get("Öğrenci", ""),
                    "Kampanya": entry.get("Kampanya", ""),
                    "Mecra": entry.get("Mecra", ""),
                }
            )
    return rows


def _coerce_number(value: Any) -> float | None:
    if value is None:
        return None
    if isinstance(value, (int, float)):
        return float(value)
    text = str(value).strip().replace(",", "")
    if not text:
        return None
    try:
        return float(text)
    except ValueError:
        return None


def _extract_pie_data(rows: list[dict[str, Any]]) -> tuple[list[str], list[float]] | None:
    if not rows:
        return None
    headers = list(rows[0].keys())
    numeric_headers = []
    for header in headers:
        values = [_coerce_number(row.get(header, "")) for row in rows]
        if values and all(val is not None for val in values):
            numeric_headers.append(header)
    label_headers = [h for h in headers if h not in numeric_headers]
    if not numeric_headers or not label_headers:
        return None
    value_header = numeric_headers[0]
    label_header = label_headers[0]
    labels = [str(row.get(label_header, "")).strip() for row in rows]
    values = [_coerce_number(row.get(value_header, 0)) or 0 for row in rows]
    if not any(values):
        return None
    return labels, values


def _normalize_pie_data(
    labels: list[str], values: list[float]
) -> tuple[list[str], list[float]] | None:
    if not labels or not values:
        return None
    pairs = [(label, value) for label, value in zip(labels, values) if value > 0]
    if not pairs:
        return None
    pairs.sort(key=lambda item: item[1], reverse=True)
    max_items = 8
    if len(pairs) > max_items:
        kept = pairs[: max_items - 1]
        other_total = sum(value for _, value in pairs[max_items - 1 :])
        pairs = kept + [("Diger", other_total)]
    norm_labels = [label for label, _ in pairs]
    norm_values = [value for _, value in pairs]
    return norm_labels, norm_values


def _render_pie_chart_image(
    pdf: FPDF,
    labels: list[str],
    values: list[float],
    include_legend: bool = True,
    title: str = "",
) -> None:
    normalized = _normalize_pie_data(labels, values)
    if not normalized:
        return
    labels, values = normalized
    fig, ax = plt.subplots(figsize=(6, 5))
    colors = PDF_CHART_COLORS + ["#8c564b", "#7f7f7f", "#bcbd22", "#17becf"]

    # SmartCampus donut stili
    wedges, texts, autotexts = ax.pie(
        values,
        labels=None,
        autopct="%1.0f%%",
        startangle=90,
        colors=colors[:len(values)],
        textprops={"fontsize": 9, "color": "#fff", "fontweight": "bold"},
        pctdistance=0.78,
        wedgeprops=dict(width=0.4, edgecolor="white", linewidth=2),
    )
    for t in autotexts:
        t.set_fontsize(8)
        t.set_color("#fff")
        t.set_fontweight("bold")

    # Orta metin
    total = sum(values)
    ax.text(0, 0, f"{total:.0f}", ha="center", va="center",
            fontsize=18, fontweight="bold", color="#94A3B8")

    chart_title = title or "Dagilim"
    ax.set_title(chart_title, fontsize=11, fontweight="bold", color="#94A3B8", pad=12)
    ax.axis("equal")

    # Legend (sagda)
    ax.legend(
        labels, loc="center left", bbox_to_anchor=(1, 0.5),
        fontsize=8, frameon=False,
    )
    fig.subplots_adjust(right=0.72)

    buf = io.BytesIO()
    fig.savefig(buf, format="png", dpi=150, bbox_inches="tight",
                facecolor="white", edgecolor="none")
    plt.close(fig)
    buf.seek(0)
    tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".png")
    try:
        tmp.write(buf.read())
        tmp.close()
        pdf.image(tmp.name, w=160)
    finally:
        try:
            os.unlink(tmp.name)
        except OSError:
            pass

def _render_bar_chart_image(
    pdf: FPDF,
    labels: list[str],
    values: list[float],
    title: str = "Sutun Grafigi",
    color: str = PDF_BAR_COLOR,
) -> None:
    if not labels or not values or not any(values):
        return
    fig, ax = plt.subplots(figsize=(8, max(2.5, len(labels) * 0.45)))

    # SmartCampus yatay bar stili
    bar_colors = PDF_CHART_COLORS[:len(labels)] if len(labels) <= 8 else [color] * len(labels)
    bars = ax.barh(labels, values, color=bar_colors, height=0.6, edgecolor="white", linewidth=1)
    ax.set_title(title, fontsize=11, fontweight="bold", color="#94A3B8", pad=12)
    ax.invert_yaxis()
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)
    ax.spines["left"].set_color("#e2e8f0")
    ax.spines["bottom"].set_color("#e2e8f0")
    ax.tick_params(axis="y", labelsize=8, colors="#475569")
    ax.tick_params(axis="x", labelsize=8, colors="#94a3b8")

    # Değer etiketleri
    max_val = max(values) if values else 1
    for bar, val in zip(bars, values):
        ax.text(bar.get_width() + max_val * 0.02, bar.get_y() + bar.get_height() / 2,
                f"{val:.0f}", va="center", fontsize=8, color="#94A3B8", fontweight="bold")

    fig.tight_layout()
    buf = io.BytesIO()
    fig.savefig(buf, format="png", dpi=150, bbox_inches="tight",
                facecolor="white", edgecolor="none")
    plt.close(fig)
    buf.seek(0)
    tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".png")
    try:
        tmp.write(buf.read())
        tmp.close()
        pdf.image(tmp.name, w=170)
    finally:
        try:
            os.unlink(tmp.name)
        except OSError:
            pass


def _find_test_pdf_path(test_file: str) -> Path | None:
    if not test_file:
        return None
    candidate = Path(".streamlit") / test_file
    if candidate.exists():
        return candidate
    filename = Path(test_file).name
    for path in Path(".streamlit").rglob(filename):
        if path.is_file():
            return path
    return None


@st.cache_data(show_spinner=False)
def _load_pdf_bytes(path_str: str) -> bytes:
    return Path(path_str).read_bytes()


@st.cache_data(show_spinner=False)
def _extract_answer_key_from_pdf(path_str: str) -> list[str]:
    if PyPDF2 is None:
        return []
    pdf_path = Path(path_str)
    if not pdf_path.exists():
        return []
    reader = PyPDF2.PdfReader(pdf_path)
    if not reader.pages:
        return []
    text = reader.pages[-1].extract_text() or ""
    pairs = re.findall(r"(\\d+)\\.\\s*([A-D])", text)
    if not pairs:
        return []
    answers = [letter for _, letter in pairs]
    return answers


@st.cache_data(show_spinner=False)
def _build_pdf_preview_bytes(path_str: str, max_pages: int = 3) -> bytes:
    if PyPDF2 is None:
        return b""
    pdf_path = Path(path_str)
    if not pdf_path.exists():
        return b""
    reader = PyPDF2.PdfReader(str(pdf_path))
    if not reader.pages:
        return b""
    writer = PyPDF2.PdfWriter()
    for page in reader.pages[:max_pages]:
        writer.add_page(page)
    buf = io.BytesIO()
    writer.write(buf)
    return buf.getvalue()


@st.cache_data(show_spinner=False)
def _render_pdf_preview_images(path_str: str, max_pages: int = 3) -> list[bytes]:
    if fitz is None:
        return []
    pdf_path = Path(path_str)
    if not pdf_path.exists():
        return []
    try:
        doc = fitz.open(pdf_path)
    except Exception:
        return []
    images: list[bytes] = []
    zoom = 1.3
    mat = fitz.Matrix(zoom, zoom)
    for page in doc[:max_pages]:
        pix = page.get_pixmap(matrix=mat)
        images.append(pix.tobytes("png"))
    return images


@st.cache_data(show_spinner=False)
def _get_pdf_page_count(path_str: str) -> int:
    if fitz is None:
        return 0
    pdf_path = Path(path_str)
    if not pdf_path.exists():
        return 0
    try:
        doc = fitz.open(pdf_path)
    except Exception:
        return 0
    return doc.page_count


@st.cache_data(show_spinner=False)
def _render_pdf_page_image(path_str: str, page_index: int) -> bytes | None:
    if fitz is None:
        return None
    pdf_path = Path(path_str)
    if not pdf_path.exists():
        return None
    try:
        doc = fitz.open(pdf_path)
    except Exception:
        return None
    if page_index < 0 or page_index >= doc.page_count:
        return None
    zoom = 1.3
    mat = fitz.Matrix(zoom, zoom)
    page = doc.load_page(page_index)
    pix = page.get_pixmap(matrix=mat)
    return pix.tobytes("png")


def generate_level_exam_pdf(
    title: str,
    lead_label: str,
    subject_rows: list[dict[str, Any]],
    summary_rows: list[dict[str, Any]],
    labels: list[str],
    values: list[float],
    student_name: str = "",
    student_class: str = "",
    outcome_rows: list[dict[str, Any]] | None = None,
    need_labels: list[str] | None = None,
    need_values: list[float] | None = None,
    recommendation_rows: list[dict[str, Any]] | None = None,
    section_pies: list[tuple[str, list[str], list[float]]] | None = None,
) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    pdf.add_page()
    subtitle = f"Aday: {lead_label}" if lead_label else ""
    _add_pdf_header(pdf, title, subtitle)
    if student_name or student_class:
        pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
        if student_name:
            pdf.multi_cell(0, 6, pdf_safe(f"Öğrenci: {student_name}"))
        if student_class:
            pdf.multi_cell(0, 6, pdf_safe(f"Sınıf/Şube: {student_class}"))
        pdf.ln(2)

    if summary_rows:
        pdf.ln(2)
        _render_pdf_table(pdf, summary_rows)
    if subject_rows:
        pdf.ln(2)
        _render_pdf_table(pdf, subject_rows)

    if values and any(values):
        chart_height = 110
        if pdf.get_y() + chart_height > pdf.h - pdf.b_margin:
            pdf.add_page()
            _add_pdf_header(pdf, "Ders Dagilimi")
        else:
            pdf.ln(4)
        _render_bar_chart_image(pdf, labels, values, title="Ders Bazli Dogru", color=PDF_BAR_COLOR)
        pdf.ln(4)
        _render_pie_chart_image(pdf, labels, values, include_legend=False)

    if outcome_rows:
        pdf.add_page()
        _add_pdf_header(pdf, "Kazanim Başarı Tablosu")
        _render_pdf_table(pdf, outcome_rows)

    if need_labels and need_values and any(need_values):
        pdf.add_page()
        _add_pdf_header(pdf, "Ihtiyac Dagilimi")
        _render_pie_chart_image(pdf, need_labels, need_values, include_legend=True)

    if recommendation_rows:
        pdf.add_page()
        _add_pdf_header(pdf, "Ders Bazinda Oneriler")
        _render_pdf_table(pdf, recommendation_rows)

    if section_pies:
        pdf.add_page()
        _add_pdf_header(pdf, "Bolum Bazli Grafikler")
        for title_row, pie_labels, pie_values in section_pies:
            if not pie_labels or not pie_values:
                continue
            pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
            pdf.cell(0, 6, pdf_safe(title_row), ln=1)
            _render_pie_chart_image(pdf, pie_labels, pie_values, include_legend=True)
            pdf.ln(4)

    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def generate_vark_pdf(
    title: str,
    lead_label: str,
    counts: dict[str, int],
    total_questions: int,
    dominant_styles: list[str],
    percents: dict[str, int],
    primary: str,
    secondary: str,
    label: str,
) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    pdf.add_page()
    subtitle = f"Aday: {lead_label}" if lead_label else ""
    _add_pdf_header(pdf, title, subtitle)

    style_names = {
        "V": "Gorsel (V)",
        "A": "Isitsel (A)",
        "R": "Okuma/Yazma (R)",
        "K": "Kinestetik (K)",
    }
    summary_rows = [
        {"Kalem": "Toplam Soru", "Deger": str(total_questions)},
        {"Kalem": "Gorsel (V)", "Deger": str(counts.get("V", 0))},
        {"Kalem": "Isitsel (A)", "Deger": str(counts.get("A", 0))},
        {"Kalem": "Okuma/Yazma (R)", "Deger": str(counts.get("R", 0))},
        {"Kalem": "Kinestetik (K)", "Deger": str(counts.get("K", 0))},
        {"Kalem": "V %", "Deger": f"%{percents.get('V', 0)}"},
        {"Kalem": "A %", "Deger": f"%{percents.get('A', 0)}"},
        {"Kalem": "R %", "Deger": f"%{percents.get('R', 0)}"},
        {"Kalem": "K %", "Deger": f"%{percents.get('K', 0)}"},
        {"Kalem": "Birincil Stil", "Deger": primary or "-"},
        {"Kalem": "Ikincil Stil", "Deger": secondary or "-"},
        {"Kalem": "Etiket", "Deger": label},
        {
            "Kalem": "Baskin Stiller",
            "Deger": ", ".join(style_names.get(s, s) for s in dominant_styles) or "-",
        },
    ]
    _render_pdf_table(pdf, summary_rows)

    labels = [
        "Gorsel (V)",
        "Isitsel (A)",
        "Okuma/Yazma (R)",
        "Kinestetik (K)",
    ]
    values = [
        float(counts.get("V", 0)),
        float(counts.get("A", 0)),
        float(counts.get("R", 0)),
        float(counts.get("K", 0)),
    ]
    if any(values):
        pdf.ln(4)
        _render_pie_chart_image(pdf, labels, values, include_legend=True)

    recommendations = {
        "V": [
            "Zihin haritasi, sema ve renk kodlu ozetler kullan.",
            "Gorsel kartlarla tekrar yap (kavram + ikon).",
            "Grafik/tablo ile konuyu bagla.",
        ],
        "A": [
            "Konuyu sesli anlat/tekrar et (teach-back).",
            "Dinleme calismalarina zaman ayir (podcast/ses kaydi).",
            "Soru-cevap ile ogrenmeyi pekistir.",
        ],
        "R": [
            "Özet cikart, anahtar kelimeleri yaz.",
            "Kavram sozlugu olustur (terim + kisa aciklama).",
            "Metin ustunde isaretleme ve tekrar.",
        ],
        "K": [
            "Ornek soru/cozum ve uygulama odakli calis.",
            "Kisa calisma + mini uygulama dongusu kur.",
            "Somut materyal/deney ile ogren.",
        ],
    }
    if dominant_styles:
        pdf.add_page()
        _add_pdf_header(pdf, "Oneriler (Baskin Stiller)")
        pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
        pdf.cell(0, 6, pdf_safe("Baskin Stiller"), ln=1)
        pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
        for style in dominant_styles:
            title_line = style_names.get(style, style)
            pdf.multi_cell(0, 6, pdf_safe(title_line))
            for line in recommendations.get(style, []):
                pdf.multi_cell(0, 6, pdf_safe(f"- {line}"))
            pdf.ln(1)

    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def generate_hht1_pdf(
    lead_label: str,
    student_name: str,
    student_class: str,
    student_score: int,
    parent_score: int,
    total_score: int,
    percent: int,
    level: str,
    suggestion: str,
    domain_rows: list[dict[str, Any]] | None = None,
) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    pdf.add_page()
    subtitle = f"Aday: {lead_label}" if lead_label else ""
    _add_pdf_header(pdf, "HHT-1 Sonuc Raporu", subtitle)
    pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
    if student_name:
        pdf.multi_cell(0, 6, pdf_safe(f"Öğrenci: {student_name}"))
    if student_class:
        pdf.multi_cell(0, 6, pdf_safe(f"Sınıf/Şube: {student_class}"))
    pdf.ln(2)
    summary_rows = [
        {"Kalem": "Öğrenci Bolumu", "Deger": f"{student_score}/25"},
        {"Kalem": "Veli Gozlem Bolumu", "Deger": f"{parent_score}/45"},
        {"Kalem": "Toplam", "Deger": f"{total_score}/70"},
        {"Kalem": "Yuzde", "Deger": f"%{percent}"},
        {"Kalem": "Seviye", "Deger": level},
    ]
    _render_pdf_table(pdf, summary_rows)
    # Ogrenci vs Veli bolum dagilimi
    if student_score or parent_score:
        pdf.ln(2)
        pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
        pdf.cell(0, 6, "Bolum Dagilimi (Öğrenci/Veli)", ln=1)
        pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
        labels = ["Öğrenci", "Veli"]
        values = [float(student_score), float(parent_score)]
        _render_pie_chart_image(pdf, labels, values, include_legend=True)
    if domain_rows:
        pdf.ln(2)
        pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
        pdf.cell(0, 6, "Alan Bazli Başarı (Öğrenci)", ln=1)
        pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
        _render_pdf_table(pdf, domain_rows)
        # Alan bazli pasta grafik
        labels = [row.get("Alan", "") for row in domain_rows]
        values = []
        for row in domain_rows:
            raw = str(row.get("Başarı %", "0")).replace("%", "")
            try:
                values.append(float(raw))
            except ValueError:
                values.append(0.0)
        if any(values):
            pdf.ln(2)
            pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
            pdf.cell(0, 6, "Alan Bazli Pasta Grafik", ln=1)
            pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
            _render_pie_chart_image(pdf, labels, values, include_legend=True)
    pdf.ln(2)
    pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
    pdf.cell(0, 6, "Oneri (otomatik)", ln=1)
    pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
    pdf.multi_cell(0, 6, pdf_safe(suggestion))
    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def _add_pie_chart_page(pdf: FPDF, title: str, labels: list[str], values: list[float]) -> None:
    if not labels or not values:
        return
    pdf.add_page()
    _add_pdf_header(pdf, title, "Grafik")
    _render_pie_chart_image(pdf, labels, values, include_legend=True)


def _add_pdf_header(pdf: FPDF, title: str, subtitle: str | None = None) -> None:
    profile = load_kim_profile()
    school_name = profile.get("name") or st.session_state.get("tenant_name", "")
    logo_path = resolve_logo_path(profile)
    header_top = PDF_MARGIN
    text_x = 10
    logo_height = 0
    if logo_path:
        try:
            pdf.image(logo_path, x=10, y=header_top, w=22, h=22)
            text_x = 38
            logo_height = 22
        except Exception:
            logo_path = ""
    pdf.set_text_color(*PDF_HEADER_TEXT)
    pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
    pdf.set_xy(0, header_top)
    pdf.cell(0, 6, pdf_safe(school_name), ln=1, align="C")
    pdf.set_text_color(*PDF_HEADER_TEXT)
    pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
    pdf.cell(0, 8, pdf_safe(title), ln=1, align="C")
    if subtitle:
        pdf.set_text_color(*PDF_SUBTITLE_TEXT)
        pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
        pdf.cell(0, 6, pdf_safe(subtitle), ln=1, align="C")
    header_bottom = max(pdf.get_y(), header_top + logo_height + 2)
    pdf.set_y(header_bottom)
    pdf.set_x(PDF_MARGIN)
    pdf.ln(6)


def _fallback_pdf_text(title: str, rows: list[dict[str, Any]]) -> bytes:
    lines: list[str] = [title]
    if not rows:
        lines.append("Veri bulunamadı.")
    else:
        for idx, row in enumerate(rows, start=1):
            lines.append(f"Satir {idx}")
            for key, value in row.items():
                lines.append(f"  {key}: {value}")
    return "\n".join(lines).encode("utf-8")


def _safe_generate_pdf(rows: list[dict[str, Any]], title: str) -> bytes:
    pdf_bytes = generate_pdf_report(rows, title)
    if pdf_bytes:
        return pdf_bytes
    return _fallback_pdf_text(title, rows)


def generate_pdf_report(rows: list[dict[str, Any]], title: str) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    pdf.add_page()
    _add_pdf_header(pdf, title)
    if not rows:
        pdf.set_font(PDF_FONT, size=PDF_FONT_SIZE)
        pdf.cell(0, 6, "Veri bulunamadı.", ln=1)
    else:
        _render_pdf_table(pdf, rows)
        pie_data = _extract_pie_data(rows)
        if pie_data:
            labels, values = pie_data
            if title in {"Planlanan Kampanya Performansi", "Planlanan Mecra Performansi"}:
                _add_pie_chart_page(pdf, title, labels, values)
            else:
                chart_height = 110
                if pdf.get_y() + chart_height > pdf.h - pdf.b_margin:
                    _add_pie_chart_page(pdf, title, labels, values)
                else:
                    pdf.ln(4)
                _render_pie_chart_image(pdf, labels, values, include_legend=False)
    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def generate_plan_pdf(
    plan_rows: list[dict[str, Any]],
    counts_rows: list[dict[str, Any]],
    title: str = "Kampanya Planlama Raporu",
    include_summary: bool = False,
    summary_rows: list[dict[str, Any]] | None = None,
) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    pdf.add_page()
    _add_pdf_header(pdf, title)
    if not plan_rows:
        pdf.set_font(PDF_FONT, size=PDF_FONT_SIZE)
        pdf.cell(0, 6, "Veri bulunamadı.", ln=1)
    else:
        _render_pdf_table(pdf, plan_rows)

    if counts_rows:
        pdf.add_page()
        _add_pdf_header(pdf, "Planlanan Kampanya Dagilimi")
        _render_pdf_table(pdf, counts_rows)
        headers = list(counts_rows[0].keys())
        labels = [str(row.get(headers[0], "")).strip() for row in counts_rows]
        values = [_coerce_number(row.get(headers[1], 0)) or 0 for row in counts_rows]
        if any(values):
            chart_block_height = 240
            if pdf.get_y() + chart_block_height > pdf.h - pdf.b_margin:
                pdf.add_page()
                _add_pdf_header(pdf, "Planlanan Kampanya Dagilimi", "Grafikler")
            pdf.ln(4)
            _render_bar_chart_image(pdf, labels, values)
            pdf.ln(4)
            _render_pie_chart_image(pdf, labels, values, include_legend=False)
    if include_summary and summary_rows:
        pdf.add_page()
        _add_pdf_header(pdf, "Otomatik 12 Ay Plan Özeti")
        _render_pdf_table(pdf, summary_rows)
    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def generate_simple_pdf(title: str, lines: list[str]) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    pdf.add_page()
    _add_pdf_header(pdf, title)
    if not lines:
        pdf.set_font(PDF_FONT, size=PDF_FONT_SIZE)
        pdf.cell(0, 6, "Veri bulunamadı.", ln=1)
    else:
        table_rows = []
        text_lines = []
        for line in lines:
            if ":" in line:
                label, value = line.split(":", 1)
                table_rows.append(
                    {"Kalem": label.strip(), "Deger": value.strip()}
                )
            else:
                text_lines.append(line)
        if table_rows:
            usable_width = pdf.w - pdf.l_margin - pdf.r_margin
            col_widths = [min(80, usable_width * 0.4), usable_width * 0.6]
            _render_pdf_table(pdf, table_rows, headers=["Kalem", "Deger"], col_widths=col_widths)
        for line in text_lines:
            pdf.multi_cell(0, 6, pdf_safe(line))
    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def generate_multi_intelligence_pdf(
    title: str,
    lead_label: str,
    totals_sorted: list[tuple[str, int, str, int, list[str]]],
    top3: list[tuple[str, int, str, int, list[str]]],
    interpretation_map: dict[str, dict[str, Any]],
) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    pdf.add_page()
    subtitle = f"Aday: {lead_label}" if lead_label else ""
    _add_pdf_header(pdf, title, subtitle)

    pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
    pdf.cell(0, 6, "Baskin 3 Alan", ln=1)
    pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
    for idx, (name, score, level_name, _, _) in enumerate(top3, start=1):
        pdf.multi_cell(0, 6, pdf_safe(f"{idx}) {name} - {score}/10 ({level_name})"))
    pdf.ln(2)

    table_rows = [
        {"Alan": t[0], "Skor": f"{t[1]}/10", "Seviye": t[2], "Yuzde": f"{t[3]}%"}
        for t in totals_sorted
    ]
    _render_pdf_table(pdf, table_rows)

    labels = [t[0] for t in totals_sorted]
    values = [t[1] for t in totals_sorted]
    if any(values):
        chart_height = 110
        if pdf.get_y() + chart_height > pdf.h - pdf.b_margin:
            pdf.add_page()
            _add_pdf_header(pdf, "Çoklu Zeka Dagilimi")
        else:
            pdf.ln(4)
        _render_pie_chart_image(pdf, labels, values, include_legend=False)

    pdf.ln(4)
    pdf.set_font(PDF_FONT, "B", PDF_FONT_SIZE)
    pdf.cell(0, 6, "Testin Yorumlanmasi (Güçlü 3 Alan)", ln=1)
    pdf.set_font(PDF_FONT, "", PDF_FONT_SIZE)
    for name, _, _, _, _ in top3:
        info = interpretation_map.get(name)
        if not info:
            continue
        pdf.multi_cell(0, 6, pdf_safe(name))
        pdf.multi_cell(0, 6, pdf_safe(f"Ne demekd {info['desc']}"))
        pdf.multi_cell(0, 6, pdf_safe("Danismanin konusmasi:"))
        pdf.multi_cell(0, 6, pdf_safe(info["speech"]))
        pdf.multi_cell(0, 6, pdf_safe("Nasil calismali?"))
        for line in info["study"]:
            pdf.multi_cell(0, 6, pdf_safe(f"- {line}"))
        pdf.multi_cell(0, 6, pdf_safe("Teknikler"))
        for line in info["tech"]:
            pdf.multi_cell(0, 6, pdf_safe(f"- {line}"))
        pdf.multi_cell(0, 6, pdf_safe("Uygun ders/alanlar"))
        for line in info["fit"]:
            pdf.multi_cell(0, 6, pdf_safe(f"- {line}"))
        pdf.multi_cell(0, 6, pdf_safe("Dusuk ciktiysa"))
        pdf.multi_cell(0, 6, pdf_safe(info["low"]))
        pdf.ln(2)

    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def generate_candidate_pdf(
    lead: dict[str, Any],
    invites: list[dict[str, Any]],
    meetings: list[dict[str, Any]],
    needs_counts: Counter,
    needs_selection_counts: Counter,
    flow_label_counts: Counter,
    meeting_results: list[dict[str, Any]] | None = None,
) -> bytes | None:
    """Modern tasarımlı öğrenci bireysel raporu PDF oluşturur."""
    try:
        from reportlab.lib.pagesizes import A4
        from reportlab.pdfgen import canvas
        from reportlab.lib.units import cm
        from reportlab.lib.utils import ImageReader
        import io
        import matplotlib
        matplotlib.use('Agg')
        import matplotlib.pyplot as plt
    except ImportError:
        return None

    font_name, font_bold = _ensure_turkish_pdf_fonts()

    buffer = io.BytesIO()
    width, height = A4
    c = canvas.Canvas(buffer, pagesize=A4)

    # Yardımcı fonksiyonlar
    def safe_text(text: Any) -> str:
        if text is None:
            return ""
        return str(text)

    def new_page():
        c.showPage()
        return height - 2.5*cm

    def check_page(current_y, needed=2*cm):
        if current_y < needed + 2*cm:
            return new_page()
        return current_y

    # Renk paleti
    COLORS = {
        "primary": (0.15, 0.39, 0.76),      # Mavi
        "secondary": (0.09, 0.47, 0.31),     # Yeşil
        "accent": (0.55, 0.36, 0.96),        # Mor
        "warning": (0.96, 0.62, 0.04),       # Turuncu
        "danger": (0.86, 0.15, 0.15),        # Kırmızı
        "success": (0.06, 0.65, 0.42),       # Yeşil
        "info": (0.06, 0.59, 0.85),          # Açık mavi
        "dark": (0.12, 0.23, 0.37),          # Koyu lacivert
    }

    # Bölüm renkleri
    SECTION_COLORS = {
        "Öğrenci Bilgileri": COLORS["primary"],
        "Veli Bilgileri": COLORS["info"],
        "Kampanya": COLORS["secondary"],
        "Sozlesme Bilgileri": COLORS["success"],
        "İşlem Geçmişi": COLORS["accent"],
        "Ihtiyac Analizi": COLORS["warning"],
        "Fiyat": COLORS["danger"],
        "Görüşme": COLORS["dark"],
        "Arama": COLORS["info"],
        "Rapor": COLORS["primary"],
    }

    def get_section_color(section_name):
        for key, color in SECTION_COLORS.items():
            if key.lower() in section_name.lower():
                return color
        return COLORS["dark"]

    def create_pie_chart(data: dict, title: str) -> io.BytesIO | None:
        if not data or all(v == 0 for v in data.values()):
            return None
        try:
            fig, ax = plt.subplots(figsize=(5, 4.5))
            chart_colors = PDF_CHART_COLORS + ["#8c564b", "#7f7f7f", "#bcbd22", "#17becf"]
            wedges, texts, autotexts = ax.pie(
                list(data.values()),
                labels=None,
                autopct='%1.0f%%',
                colors=chart_colors[:len(data)],
                startangle=90,
                pctdistance=0.78,
                wedgeprops=dict(width=0.4, edgecolor="white", linewidth=2),
            )
            for autotext in autotexts:
                autotext.set_fontsize(8)
                autotext.set_color("#fff")
                autotext.set_fontweight("bold")
            total = sum(data.values())
            ax.text(0, 0, f"{total:.0f}", ha="center", va="center",
                    fontsize=16, fontweight="bold", color="#94A3B8")
            ax.legend(
                [safe_text(k)[:20] for k in data.keys()],
                loc="center left", bbox_to_anchor=(1, 0.5),
                fontsize=7, frameon=False,
            )
            ax.set_title(safe_text(title), fontsize=10, fontweight='bold', color="#94A3B8")
            fig.subplots_adjust(right=0.72)
            buf = io.BytesIO()
            plt.savefig(buf, format='png', dpi=150, bbox_inches='tight', facecolor='white')
            plt.close(fig)
            buf.seek(0)
            return buf
        except Exception:
            return None

    def create_bar_chart(data: dict, title: str) -> io.BytesIO | None:
        if not data or all(v == 0 for v in data.values()):
            return None
        try:
            chart_colors = PDF_CHART_COLORS[:len(data)]
            fig, ax = plt.subplots(figsize=(5, max(2.5, len(data) * 0.4)))
            bars = ax.barh(
                [safe_text(k)[:25] for k in list(data.keys())[:8]],
                list(data.values())[:8],
                color=chart_colors[:len(data)],
                height=0.6, edgecolor="white", linewidth=1,
            )
            ax.invert_yaxis()
            ax.set_title(safe_text(title), fontsize=10, fontweight='bold', color="#94A3B8")
            ax.spines["top"].set_visible(False)
            ax.spines["right"].set_visible(False)
            ax.spines["left"].set_color("#e2e8f0")
            ax.spines["bottom"].set_color("#e2e8f0")
            ax.tick_params(axis="y", labelsize=8, colors="#475569")
            ax.tick_params(axis="x", labelsize=8, colors="#94a3b8")
            max_val = max(data.values()) if data.values() else 1
            for bar, val in zip(bars, list(data.values())[:8]):
                ax.text(bar.get_width() + max_val * 0.02, bar.get_y() + bar.get_height()/2,
                        str(val), va='center', fontsize=8, color="#94A3B8", fontweight="bold")
            plt.tight_layout()
            buf = io.BytesIO()
            plt.savefig(buf, format='png', dpi=150, bbox_inches='tight', facecolor='white')
            plt.close(fig)
            buf.seek(0)
            return buf
        except Exception:
            return None

    # Verileri hazırla
    report_rows = _build_candidate_report_rows(lead, invites, meetings, meeting_results)
    sections: dict[str, list[dict[str, Any]]] = {}
    for row in report_rows:
        sections.setdefault(row["Bolum"], []).append(row)

    profile = load_kim_profile()
    school_name = profile.get("name") or st.session_state.get("tenant_name", "")
    ogrenci_adi = lead.get('student_name', '') or lead.get('name', '')
    veli_adi = lead.get('name', '')

    # ===== SAYFA 1: KAPAK =====
    # Üst banner
    c.setFillColorRGB(*COLORS["dark"])
    c.rect(0, height - 3.5*cm, width, 3.5*cm, fill=True)

    # Başlık
    c.setFillColorRGB(1, 1, 1)
    c.setFont(font_bold, 18)
    c.drawCentredString(width/2, height - 1.5*cm, safe_text(school_name))
    c.setFont(font_name, 11)
    c.drawCentredString(width/2, height - 2.3*cm, "OGRENCI BIREYSEL RAPORU")
    c.setFont(font_bold, 9)
    c.drawCentredString(width/2, height - 3*cm, f"Rapor Tarihi: {datetime.now().strftime('%d.%m.%Y %H:%M')}")

    y = height - 5*cm

    # Öğrenci bilgi kartı
    c.setFillColorRGB(*COLORS["primary"])
    c.roundRect(1.5*cm, y - 3*cm, width - 3*cm, 3.2*cm, 0.3*cm, fill=True)
    c.setFillColorRGB(1, 1, 1)
    c.setFont(font_bold, 14)
    c.drawString(2*cm, y - 0.8*cm, f"Öğrenci: {safe_text(ogrenci_adi)}")
    c.setFont(font_name, 11)
    c.drawString(2*cm, y - 1.5*cm, f"Veli: {safe_text(veli_adi)}")
    c.drawString(2*cm, y - 2.1*cm, f"Telefon: {safe_text(lead.get('phone', ''))}")
    c.drawString(10*cm, y - 1.5*cm, f"Kademe: {safe_text(lead.get('kademe', ''))}")
    c.drawString(10*cm, y - 2.1*cm, f"Sınıf: {safe_text(lead.get('current_grade', ''))}")
    c.drawString(2*cm, y - 2.7*cm, f"Durum: {safe_text(lead.get('status', ''))}")
    y -= 4*cm

    # Özet istatistikler - renkli kartlar
    meeting_rows = [m for m in meetings if m.get("Aday") == lead.get("name") and m.get("Öğrenci") == lead.get("student_name")]
    invite_rows = [i for i in invites if i.get("Aday") == lead.get("name") and i.get("Öğrenci") == lead.get("student_name")]

    stats = [
        ("Toplam Görüşme", len(meeting_rows), COLORS["success"]),
        ("Toplam Arama", len(invite_rows), COLORS["info"]),
        ("Ihtiyac Kategorisi", len(needs_counts) if needs_counts else 0, COLORS["warning"]),
        ("Veli Sorusu", sum(Counter(_collect_parent_question_labels(meetings, lead)).values()), COLORS["accent"]),
    ]

    card_width = (width - 4*cm) / 4
    for idx, (label, value, color) in enumerate(stats):
        x = 1.5*cm + idx * card_width + 0.1*cm
        c.setFillColorRGB(*color)
        c.roundRect(x, y - 2*cm, card_width - 0.2*cm, 2*cm, 0.2*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 18)
        c.drawCentredString(x + card_width/2 - 0.1*cm, y - 1*cm, str(value))
        c.setFont(font_name, 8)
        c.drawCentredString(x + card_width/2 - 0.1*cm, y - 1.6*cm, safe_text(label))
    y -= 3*cm

    # ===== BÖLÜMLER =====
    section_order = ["Öğrenci Bilgileri", "Veli Bilgileri", "Kampanya", "Sozlesme Bilgileri"]
    remaining_sections = [s for s in sections.keys() if s not in section_order and "İşlem Geçmişi" not in s]
    history_sections = [s for s in sections.keys() if "İşlem Geçmişi" in s]

    for section_name in section_order + remaining_sections:
        if section_name not in sections:
            continue
        rows = sections[section_name]

        y = check_page(y, 3*cm)
        color = get_section_color(section_name)

        # Bölüm başlığı
        c.setFillColorRGB(*color)
        c.roundRect(1.5*cm, y - 0.7*cm, width - 3*cm, 0.8*cm, 0.15*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 10)
        c.drawString(2*cm, y - 0.5*cm, safe_text(section_name.upper()))
        y -= 1.2*cm

        # Tablo
        c.setFillColorRGB(*color[:3])
        c.setStrokeColorRGB(*color)
        row_height = 0.5*cm
        col1_width = 5*cm
        col2_width = width - 3*cm - col1_width

        for idx, row in enumerate(rows):
            y = check_page(y, 0.6*cm)
            # Alternatif satır rengi
            if idx % 2 == 0:
                c.setFillColorRGB(0.97, 0.97, 0.99)
            else:
                c.setFillColorRGB(1, 1, 1)
            c.rect(1.5*cm, y - row_height, width - 3*cm, row_height, fill=True)

            c.setFillColorRGB(0.2, 0.2, 0.2)
            c.setFont(font_bold, 8)
            c.drawString(1.7*cm, y - 0.35*cm, safe_text(row.get("Alan", ""))[:30])
            c.setFont(font_name, 8)
            c.drawString(1.7*cm + col1_width, y - 0.35*cm, safe_text(row.get("Deger", ""))[:60])
            y -= row_height
        y -= 0.5*cm

    # ===== İŞLEM GEÇMİŞİ (son 10) =====
    if history_sections:
        y = new_page()
        c.setFillColorRGB(*COLORS["accent"])
        c.rect(0, height - 2.5*cm, width, 2.5*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 14)
        c.drawCentredString(width/2, height - 1.5*cm, "ISLEM GECMISI")
        y = height - 4*cm

        # Tablo başlığı
        c.setFillColorRGB(*COLORS["accent"])
        c.rect(1.5*cm, y - 0.6*cm, width - 3*cm, 0.7*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 8)
        c.drawString(1.7*cm, y - 0.4*cm, "Tarih")
        c.drawString(4*cm, y - 0.4*cm, "Saat")
        c.drawString(6*cm, y - 0.4*cm, "İşlem")
        c.drawString(10*cm, y - 0.4*cm, "Sonuc")
        c.drawString(14*cm, y - 0.4*cm, "Yapan")
        y -= 0.8*cm

        for section_name in sorted(history_sections)[:10]:
            rows = sections[section_name]
            y = check_page(y, 0.6*cm)
            tarih = saat = islem = sonuc = yapan = ""
            for row in rows:
                if row.get("Alan") == "Tarih":
                    tarih = row.get("Deger", "")
                elif row.get("Alan") == "Saat":
                    saat = row.get("Deger", "")
                elif row.get("Alan") == "İşlem":
                    islem = row.get("Deger", "")
                elif row.get("Alan") == "Sonuc":
                    sonuc = row.get("Deger", "")
                elif row.get("Alan") == "Yapan":
                    yapan = row.get("Deger", "")

            # Alternatif satır rengi
            idx = sorted(history_sections).index(section_name)
            if idx % 2 == 0:
                c.setFillColorRGB(0.96, 0.95, 1)
            else:
                c.setFillColorRGB(1, 1, 1)
            c.rect(1.5*cm, y - 0.5*cm, width - 3*cm, 0.55*cm, fill=True)

            c.setFillColorRGB(0, 0, 0)
            c.setFont(font_name, 8)
            c.drawString(1.7*cm, y - 0.35*cm, safe_text(tarih)[:10])
            c.drawString(4*cm, y - 0.35*cm, safe_text(saat)[:8])
            c.drawString(6*cm, y - 0.35*cm, safe_text(islem)[:20])
            c.drawString(10*cm, y - 0.35*cm, safe_text(sonuc)[:20])
            c.drawString(14*cm, y - 0.35*cm, safe_text(yapan)[:15])
            y -= 0.55*cm

    # ===== VELİ İHTİYAÇ ANALİZİ SAYFA =====
    if needs_counts:
        y = new_page()
        c.setFillColorRGB(*COLORS["warning"])
        c.rect(0, height - 2.5*cm, width, 2.5*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 14)
        c.drawCentredString(width/2, height - 1.5*cm, "VELI IHTIYAC ANALIZI")
        y = height - 4*cm

        # Tablo
        c.setFillColorRGB(0.75, 0.48, 0.03)
        c.rect(1.5*cm, y - 0.6*cm, width - 3*cm, 0.7*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 9)
        c.drawString(2*cm, y - 0.4*cm, "Kategori")
        c.drawString(14*cm, y - 0.4*cm, "Sayı")
        y -= 0.8*cm

        for idx, (category, count) in enumerate(needs_counts.most_common()):
            y = check_page(y, 0.6*cm)
            if idx % 2 == 0:
                c.setFillColorRGB(1, 0.98, 0.93)
            else:
                c.setFillColorRGB(1, 1, 1)
            c.rect(1.5*cm, y - 0.5*cm, width - 3*cm, 0.55*cm, fill=True)
            c.setFillColorRGB(0, 0, 0)
            c.setFont(font_name, 9)
            c.drawString(2*cm, y - 0.35*cm, safe_text(category)[:50])
            c.setFont(font_bold, 9)
            c.drawString(14*cm, y - 0.35*cm, str(count))
            y -= 0.55*cm

        # Pasta grafik
        y -= 1*cm
        pie_chart = create_pie_chart(dict(needs_counts.most_common(8)), "Ihtiyac Dagilimi")
        if pie_chart:
            y = check_page(y, 6*cm)
            c.drawImage(ImageReader(pie_chart), 3*cm, y - 5*cm, width=12*cm, height=5*cm, preserveAspectRatio=True)
            y -= 5.5*cm

    # ===== VELİ SORULARI SAYFASI =====
    parent_labels = _collect_parent_question_labels(meetings, lead)
    parent_counts = Counter(parent_labels)
    if parent_counts:
        y = new_page()
        c.setFillColorRGB(*COLORS["info"])
        c.rect(0, height - 2.5*cm, width, 2.5*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 14)
        c.drawCentredString(width/2, height - 1.5*cm, "VELI SORULARI ANALIZI")
        y = height - 4*cm

        # Tablo
        c.setFillColorRGB(0.04, 0.45, 0.66)
        c.rect(1.5*cm, y - 0.6*cm, width - 3*cm, 0.7*cm, fill=True)
        c.setFillColorRGB(1, 1, 1)
        c.setFont(font_bold, 8)
        c.drawString(2*cm, y - 0.4*cm, "Soru")
        c.drawString(16*cm, y - 0.4*cm, "Sayı")
        y -= 0.8*cm

        for idx, (question, count) in enumerate(parent_counts.most_common(15)):
            y = check_page(y, 0.6*cm)
            if idx % 2 == 0:
                c.setFillColorRGB(0.93, 0.97, 1)
            else:
                c.setFillColorRGB(1, 1, 1)
            c.rect(1.5*cm, y - 0.5*cm, width - 3*cm, 0.55*cm, fill=True)
            c.setFillColorRGB(0, 0, 0)
            c.setFont(font_name, 8)
            c.drawString(2*cm, y - 0.35*cm, safe_text(question)[:70])
            c.setFont(font_bold, 9)
            c.drawString(16*cm, y - 0.35*cm, str(count))
            y -= 0.55*cm

        # Bar grafik
        y -= 1*cm
        bar_chart = create_bar_chart(dict(parent_counts.most_common(8)), "En Çok Sorulan Sorular")
        if bar_chart:
            y = check_page(y, 5*cm)
            c.drawImage(ImageReader(bar_chart), 2*cm, y - 4*cm, width=14*cm, height=4*cm, preserveAspectRatio=True)
            y -= 4.5*cm

    # ===== FOOTER =====
    c.setFont(font_name, 8)
    c.setFillColorRGB(0.5, 0.5, 0.5)
    c.drawCentredString(width/2, 1.2*cm, f"Bu rapor SmartCampus AI tarafindan {datetime.now().strftime('%d.%m.%Y %H:%M')} tarihinde otomatik olusturulmustur.")

    c.save()
    return buffer.getvalue()


def generate_combined_pdf(
    sections: list[tuple[str, list[dict[str, Any]]]]
) -> bytes | None:
    if FPDF is None:
        return None
    pdf = FPDF()
    pdf.set_margins(PDF_MARGIN, PDF_MARGIN, PDF_MARGIN)
    pdf.set_auto_page_break(auto=True, margin=PDF_MARGIN)
    for title, rows in sections:
        pdf.add_page()
        _add_pdf_header(pdf, title)
        if not rows:
            pdf.set_font(PDF_FONT, size=PDF_FONT_SIZE)
            pdf.cell(0, 6, "Veri bulunamadı.", ln=1)
            continue
        _render_pdf_table(pdf, rows)
        pie_data = _extract_pie_data(rows)
        if pie_data:
            labels, values = pie_data
            if title in {"Planlanan Kampanya Performansi", "Planlanan Mecra Performansi"}:
                _add_pie_chart_page(pdf, title, labels, values)
            else:
                chart_height = 110
                if pdf.get_y() + chart_height > pdf.h - pdf.b_margin:
                    _add_pie_chart_page(pdf, title, labels, values)
                else:
                    pdf.ln(4)
                _render_pie_chart_image(pdf, labels, values, include_legend=False)
    pdf_output = pdf.output(dest="S")
    return pdf_output.encode("latin-1") if isinstance(pdf_output, str) else bytes(pdf_output)


def _safe_generate_combined_pdf(
    sections: list[tuple[str, list[dict[str, Any]]]]
) -> bytes:
    pdf_bytes = generate_combined_pdf(sections)
    if pdf_bytes:
        return pdf_bytes
    lines: list[str] = []
    for title, rows in sections:
        lines.append(title)
        if not rows:
            lines.append("  Veri bulunamadı.")
        else:
            for idx, row in enumerate(rows, start=1):
                entries = ", ".join(f"{k}: {row.get(k,'')}" for k in row.keys())
                lines.append(f"  {idx}. {entries}")
        lines.append("")
    return "\n".join(lines).encode("utf-8")


# ==================== CHARTS ====================


def plot_pie(counter: Counter | dict, title: str) -> None:
    if not counter:
        st.info("Veri bulunamadı.")
        return
    labels = list(counter.keys())
    values = list(counter.values())
    total = sum(values)
    try:
        import plotly.graph_objects as go
        from utils.chart_utils import sc_pie, SC_CHART_CFG, SC_COLORS
        fig = go.Figure(data=[go.Pie(
            labels=labels, values=values,
            marker=dict(colors=SC_COLORS[:len(labels)], line=dict(color="#fff", width=2)),
            textinfo="label+percent",
        )])
        sc_pie(fig, height=280,
               center_text=f"<b>{total}</b><br><span style='font-size:10px;color:#64748b'>{title[:12]}</span>")
        st.plotly_chart(fig, use_container_width=True, config=SC_CHART_CFG)
    except ImportError:
        # Fallback matplotlib
        fig, ax = plt.subplots()
        ax.pie(values, labels=labels, autopct="%1.1f%%", startangle=90)
        ax.set_title(title)
        st.pyplot(fig, clear_figure=True)


