def render_tab_plan(
    df_campaigns: pd.DataFrame, monthly_campaign_map: dict[str, list[dict[str, Any]]]
) -> None:
    render_pro_header(
        title="Kampanya Planlama",
        subtitle="Aylık kampanya planlaması • Havuz yönetimi • Aktivasyon takibi",
        icon="📅",
        gradient_start="#94A3B8",
        gradient_end="#2563eb"
    )

    # ---------- Veri yükleme ----------
    plan_store = load_plan()
    auto_year = datetime.now().year
    manual_plan = _build_manual_month_plan(
        plan_store.get("alternative_mecralar", []),
        auto_year,
    )
    existing_plans = plan_store.get("plans", {})

    needs_update = False
    if not existing_plans:
        plan_store["plans"] = manual_plan
        needs_update = True
    else:
        for month_name in MONTHS_TR:
            if month_name not in existing_plans:
                existing_plans[month_name] = manual_plan.get(month_name, {})
                needs_update = True
            else:
                mp = existing_plans[month_name]
                if "available_campaigns" not in mp:
                    mp["available_campaigns"] = manual_plan.get(month_name, {}).get("available_campaigns", [])
                    needs_update = True
                if "selected_campaigns" not in mp:
                    mp["selected_campaigns"] = {}
                    needs_update = True
        plan_store["plans"] = existing_plans

    if needs_update:
        plan_store["manual_plan_applied_year"] = auto_year
        plan_store["manual_plan_generated_at"] = datetime.now().isoformat(timespec="seconds")
        save_plan(plan_store)

    plans = plan_store.get("plans", {})

    # ---------- Ay seçici (en üstte, varsayılan: bu ay) ----------
    current_month_idx = datetime.now().month - 1
    col_ay, col_yenile, col_mecra = st.columns([2, 1, 1])
    with col_ay:
        month = st.selectbox("📆 Ay Seç", MONTHS_TR, index=current_month_idx, key="plan_month_select")
    with col_yenile:
        st.markdown("<div style='height:28px'></div>", unsafe_allow_html=True)
        if st.button("🔄 Havuzu Yenile", key="plan_apply_manual_campaigns", use_container_width=True):
            for mn in MONTHS_TR:
                new_avail = manual_plan.get(mn, {}).get("available_campaigns", [])
                if mn in plans:
                    plans[mn]["available_campaigns"] = new_avail
                else:
                    plans[mn] = {"available_campaigns": new_avail, "selected_campaigns": {}}
            plan_store["plans"] = plans
            plan_store["manual_plan_applied_year"] = auto_year
            plan_store["manual_plan_generated_at"] = datetime.now().isoformat(timespec="seconds")
            save_plan(plan_store)
            st.success("Havuz yenilendi!")
            trigger_rerun()
    with col_mecra:
        st.markdown("<div style='height:28px'></div>", unsafe_allow_html=True)
        with st.popover("⚙️ Mecralar"):
            render_tab_alternative_channels(show_heading=False, key_prefix="plan_")

    # ---------- Seçili ay verileri ----------
    month_plan = plans.get(month, {})
    available_campaigns = month_plan.get("available_campaigns", [])
    selected_campaigns = month_plan.get("selected_campaigns", {})

    # ---------- Özet kartlar ----------
    havuz_n = len(available_campaigns)
    aktif_n = len(selected_campaigns)
    bekleyen_n = havuz_n - aktif_n
    render_stat_cards([
        {"label": f"{month} Havuz", "value": havuz_n, "color": "#3b82f6", "icon": "📦"},
        {"label": "Aktif", "value": aktif_n, "color": "#10b981", "icon": "✅"},
        {"label": "Bekleyen", "value": bekleyen_n, "color": "#f59e0b", "icon": "⏳"},
        {"label": "Oran", "value": f"%{round(aktif_n / havuz_n * 100) if havuz_n else 0}", "color": "#8b5cf6", "icon": "📊"},
    ])

    # ==================== 2 ADIM: Aktif | Yıllık Özet ====================
