                st.session_state[f"{sozlesme_key}_ucret_yemek"] = float(ek_bilgi.get("ogle_yemegi", 0))
                st.session_state[f"{sozlesme_key}_ucret_kahvalti"] = float(ek_bilgi.get("kahvalti", 0))
                st.session_state[f"{sozlesme_key}_ucret_etut_kursu"] = float(ek_bilgi.get("etut_kursu", 0))
                st.session_state[f"{sozlesme_key}_ucret_pansiyon"] = float(ek_bilgi.get("pansiyon", 0))
                st.session_state[f"{sozlesme_key}_ucret_kitap"] = float(ek_bilgi.get("kitap_kirtasiye", 0))
                st.session_state[f"{sozlesme_key}_ucret_servis"] = float(ek_bilgi.get("servis", 0))
                st.session_state[f"{sozlesme_key}_ucret_etut"] = float(ek_bilgi.get("etut", 0))
