    # Özel Hususlar
    with st.expander("📝 Özel Hususlar", expanded=False):
        st.markdown("*(Yürürlükteki mevzuata ve bu sözleşmede yer alan şartlara aykırı olmamak kaydıyla özel şartlar belirlenebilir)*")
