def _render_invite_test_controls(
    tests: list[dict[str, Any]],
    *,
    key_prefix: str,
    lead_label: str = "",
    show_heading: bool = True,
) -> None:
    if not tests:
        if show_heading:
            st.info("Henuz test eklenmedi.")
        return
    if show_heading:
        st.markdown("### Mevcut Testler")
    active_key = f"{key_prefix}_invite_test_active"
    for idx, item in enumerate(tests, start=1):
        test_name = str(item.get("TestAdi", "")).strip()
        test_file = str(item.get("Dosya", "")).strip()
        if not test_name or not test_file:
            continue
        button_key = f"{key_prefix}_test_run_{idx}"
        if st.button(f"{idx}. {test_name} (Testi Uygula)", key=button_key):
            st.session_state[active_key] = idx
        if st.session_state.get(active_key) != idx:
            continue
        pdf_path = None
        html_bytes: bytes | None = None
        if test_file == MIDDLE_SCHOOL_TEST_KEY:
            render_middle_school_exam_test(
                f"{key_prefix}_ms_{idx}",
                lead_label=lead_label,
            )
        elif test_file == VARK_TEST_KEY:
            render_vark_learning_style_test(
                f"{key_prefix}_vark_{idx}",
                lead_label=lead_label,
            )
        elif test_file == VARK_10_12_TEST_KEY:
            render_vark_learning_style_test(
                f"{key_prefix}_vark_{idx}",
                lead_label=lead_label,
                title="Ogrenme Stili Testi (10-12 Yas) - VARK",
                questions=_vark_test_bank_10_12(),
            )
        elif test_file == VARK_13_PLUS_TEST_KEY:
            render_vark_learning_style_test(
                f"{key_prefix}_vark_{idx}",
                lead_label=lead_label,
                title="Ogrenme Stili Testi (13+ Yas) - VARK",
                questions=_vark_test_bank_13_plus(),
            )
        elif test_file == HHT1_TEST_KEY:
            render_hht1_test(
                f"{key_prefix}_hht1_{idx}",
                lead_label=lead_label,
            )
        elif test_file == ORTAOKUL_CHECKUP_TEST_KEY:
            render_ortaokul_checkup_test(
                f"{key_prefix}_oc_{idx}",
                lead_label=lead_label,
            )
        elif test_file == LANGUAGE_PLACEMENT_TEST_KEY:
            render_language_placement_exam_test(
                f"{key_prefix}_lang_{idx}",
                lead_label=lead_label,
            )
        elif test_file == HIGH_SCHOOL_TEST_KEY:
            render_high_school_exam_test(
                f"{key_prefix}_hs_{idx}",
                lead_label=lead_label,
            )
        elif test_file.lower().endswith(".pdf"):
            pdf_path = _find_test_pdf_path(test_file)
            if pdf_path:
                render_level_exam_test(
                    f"{key_prefix}_exam_{idx}",
                    pdf_path,
                    lead_label=lead_label,
                )
        else:
            test_path = os.path.join(".streamlit", test_file)
            if os.path.exists(test_path):
                with open(test_path, "rb") as handle:
                    html_bytes = handle.read()
                components.html(
                    html_bytes.decode("utf-8", errors="replace"),
                    height=1400,
                    scrolling=True,
                )
        if pdf_path and pdf_path.exists():
            pdf_bytes = _load_pdf_bytes(str(pdf_path))
            st.download_button(
                f"{idx}. {test_name} (PDF indir)",
                pdf_bytes,
                file_name=os.path.basename(str(pdf_path)),
                mime="application/pdf",
                key=f"{key_prefix}_test_download_{idx}",
            )
        if html_bytes:
            st.download_button(
                f"{idx}. {test_name} (HTML indir)",
                html_bytes,
                file_name=os.path.basename(os.path.join(".streamlit", test_file)),
                mime="text/html",
                key=f"{key_prefix}_test_download_{idx}",
            )
def render_tab_invite_tests() -> None:
    render_pro_header(
        title="Davet Uygulama Testleri",
        subtitle="Davet şablonlarını test edin ve önizleyin",
        icon="🧪",
        gradient_start="#9333ea",
        gradient_end="#a855f7"
    )

    st.markdown(
        """
        <p style="margin-top: 0.4rem; font-size: 0.95rem;">
            <strong>Yazı tipi testi:</strong>
            <span style="font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;">
                Pijamalı hasta yağız şoföre çabucak güvendi, ışık süzüldü, çiçekler örttü.
            </span>
        </p>
        """,
        unsafe_allow_html=True,
    )
    tests = ensure_default_invite_tests(load_invite_tests())

    # ==================== ADAY SECIMI VE FILTRELEME ====================
    st.markdown("### 👤 Aday Sec ve Test Uygula")

    # Adaylari yukle
    all_leads = load_leads()
    all_meeting_results = load_meeting_results()

    # Her aday için uygulanan testleri bul
    def _get_applied_tests_for_lead(lead: dict) -> set[str]:
        lead_label = f"{lead.get('name', '')} - {lead.get('student_name', '')}"
        applied: set[str] = set()
        for mr in all_meeting_results:
            if mr.get("candidate", "").lower() == lead_label.lower():
                tests_str = mr.get("DavetTestleriSecimler", "")
                if tests_str:
                    for t in tests_str.split(";"):
                        applied.add(t.strip().lower())
        return applied

    # Filtreleme secenekleri
    st.markdown("#### 🔍 Aday Ara ve Filtrele")

    filter_col1, filter_col2, filter_col3 = st.columns([2, 1, 1])

    with filter_col1:
        search_text = st.text_input(
            "Aday Ara (en az 3 karakter)",
            key="invite_test_search",
            placeholder="Veli veya ogrenci adi yazin..."
        )

    with filter_col2:
        # Kademe filtresi
        kademe_options = ["Tümü"] + sorted(set(
            lead.get("kademe", "") for lead in all_leads if lead.get("kademe")
        ))
        kademe_filter = st.selectbox(
            "Kademe",
            kademe_options,
            key="invite_test_kademe_filter"
        )

    with filter_col3:
        # Tarih filtresi
        date_filter_options = ["Tümü", "Bugün", "Bu Hafta", "Bu Ay", "Tarih Sec"]
        date_filter = st.selectbox(
            "Kayıt Tarihi",
            date_filter_options,
            key="invite_test_date_filter"
        )

    # Tarih secimi (eger "Tarih Sec" secildiyse)
    if date_filter == "Tarih Sec":
        date_col1, date_col2 = st.columns(2)
        with date_col1:
            filter_start_date = st.date_input(
                "Başlangıç",
                value=date.today() - timedelta(days=30),
                key="invite_test_filter_start"
            )
        with date_col2:
            filter_end_date = st.date_input(
                "Bitis",
                value=date.today(),
                key="invite_test_filter_end"
            )
    else:
        today = date.today()
        if date_filter == "Bugün":
            filter_start_date = filter_end_date = today
        elif date_filter == "Bu Hafta":
            filter_start_date = today - timedelta(days=today.weekday())
            filter_end_date = today
        elif date_filter == "Bu Ay":
            filter_start_date = today.replace(day=1)
            filter_end_date = today
        else:
            filter_start_date = None
            filter_end_date = None

    # Adaylari filtrele
    filtered_leads: list[dict] = []
    for lead in all_leads:
        # Arama filtresi (en az 3 karakter)
        if search_text and len(search_text) >= 3:
            search_lower = search_text.lower()
            lead_text = f"{lead.get('name', '')} {lead.get('student_name', '')}".lower()
            if search_lower not in lead_text:
                continue
        elif search_text and len(search_text) < 3:
            # 3 karakterden az ise hicbir aday gosterme
            continue

        # Kademe filtresi
        if kademe_filter != "Tümü" and lead.get("kademe") != kademe_filter:
            continue

        # Tarih filtresi
        if filter_start_date and filter_end_date:
            lead_date_str = lead.get("created_date", "")
            if lead_date_str:
                try:
                    lead_date = datetime.strptime(lead_date_str, "%Y-%m-%d").date()
                    if not (filter_start_date <= lead_date <= filter_end_date):
                        continue
                except ValueError:
                    pass

        filtered_leads.append(lead)

    # Aday listesini olustur
    if search_text and len(search_text) >= 3:
        candidate_options = []
        for lead in filtered_leads:
            lead_label = f"{lead.get('name', '')} - {lead.get('student_name', '')}"
            applied_tests = _get_applied_tests_for_lead(lead)
            test_count = len(applied_tests)
            kademe = lead.get("kademe", "")
            phone = lead.get("phone", "")
            display_label = f"{lead_label} | {kademe} | 📞 {phone} | 🧪 {test_count} test"
            candidate_options.append((display_label, lead))

        if candidate_options:
            st.markdown(f"**{len(candidate_options)} aday bulundu**")

            selected_display = st.selectbox(
                "Aday Secin",
                ["Seciniz..."] + [opt[0] for opt in candidate_options],
                key="invite_test_candidate_select"
            )

            if selected_display != "Seciniz...":
                # Secilen adayi bul
                selected_lead = None
                for display, lead in candidate_options:
                    if display == selected_display:
                        selected_lead = lead
                        break

                if selected_lead:
                    st.session_state["invite_test_selected_lead"] = selected_lead
                    lead_label = f"{selected_lead.get('name', '')} - {selected_lead.get('student_name', '')}"

                    # Secilen aday bilgisi
                    st.markdown(f"""
                    <div style="background: linear-gradient(135deg, #172554 0%, #bfdbfe 100%);
                                border: 2px solid #3b82f6; border-radius: 10px; padding: 1rem; margin: 1rem 0;">
                        <strong>📋 Secilen Aday:</strong> {lead_label}<br>
                        <span style="font-size: 0.9rem;">
                            📞 {selected_lead.get('phone', '')} |
                            🎓 {selected_lead.get('kademe', '')} |
                            📧 {selected_lead.get('email', '')}
                        </span>
                    </div>
                    """, unsafe_allow_html=True)

                    # Bu adaya uygulanan testleri goster
                    applied_tests = _get_applied_tests_for_lead(selected_lead)
                    if applied_tests:
                        st.markdown(f"**✅ Bu adaya uygulanan testler ({len(applied_tests)}):**")
                        for t in applied_tests:
                            st.markdown(f"- {t}")
                    else:
                        st.info("📭 Bu adaya henuz test uygulanmamis.")
        else:
            st.warning("Aramaniza uygun aday bulunamadı.")
    else:
        st.info("💡 Aday aramak için en az 3 karakter yazin.")
        # Session state'den secili adayi al
        selected_lead = st.session_state.get("invite_test_selected_lead")

    # Secili aday varsa test uygulama bolumu
    selected_lead = st.session_state.get("invite_test_selected_lead")

    st.markdown("---")
    st.markdown("### 🧪 Test Uygula")

    # Mevcut test turleri (ASCII-guvenli Turkce)
    TEST_TYPE_OPTIONS = {
        "Çoklu Zeka Testi": os.path.basename(PR01_INVITE_TEST_HTML),
        "Yabanci Dil Olcum Sınavı (CEFR)": LANGUAGE_PLACEMENT_TEST_KEY,
        "Ogrenme Stili Testi (7-9 Yas) - VARK": VARK_TEST_KEY,
        "Ogrenme Stili Testi (10-12 Yas) - VARK": VARK_10_12_TEST_KEY,
        "Ogrenme Stili Testi (13+ Yas) - VARK": VARK_13_PLUS_TEST_KEY,
        "1. Sınıf Hazirbulunusluk Testi (HHT-1)": HHT1_TEST_KEY,
        "Ortaokul Check-Up (5. Sınıfa Gecis)": ORTAOKUL_CHECKUP_TEST_KEY,
        "Ortaokul Seviye Tespit Sınavı": MIDDLE_SCHOOL_TEST_KEY,
        "Lise Seviye Tespit Sınavlari": HIGH_SCHOOL_TEST_KEY,
    }

    if selected_lead:
        lead_label = f"{selected_lead.get('name', '')} - {selected_lead.get('student_name', '')}"
        applied_tests = _get_applied_tests_for_lead(selected_lead)

        # Uygulanmamis testleri one cikar
        unapplied_tests = [t for t in TEST_TYPE_OPTIONS.keys() if t.lower() not in applied_tests]
        applied_test_names = [t for t in TEST_TYPE_OPTIONS.keys() if t.lower() in applied_tests]

        # Test secimi
        test_options_display = []
        for t in unapplied_tests:
            test_options_display.append(f"⏳ {t} (Bekliyor)")
        for t in applied_test_names:
            test_options_display.append(f"✅ {t} (Uygulandi)")

        col_a, col_b = st.columns(2)
        with col_a:
            test_type_choice = st.selectbox(
                "Test Turu Secin",
                test_options_display,
                key="invite_test_type_choice"
            )
            # Gercek test adini al
            if test_type_choice:
                real_test_name = test_type_choice.split(" (")[0].replace("⏳ ", "").replace("✅ ", "")

        with col_b:
            test_note = st.text_area("Not", key="invite_test_note", height=100)

        if st.button("🚀 Testi Baslat", key="invite_test_start", use_container_width=True):
            if test_type_choice:
                st.session_state["invite_test_active"] = real_test_name
                st.session_state["invite_test_active_file"] = TEST_TYPE_OPTIONS.get(real_test_name, "")

        # Aktif test varsa goster
        if st.session_state.get("invite_test_active"):
            active_test_name = st.session_state["invite_test_active"]
            active_test_file = st.session_state.get("invite_test_active_file", "")

            st.markdown("---")
            st.success(f"🎯 **{active_test_name}** testi **{lead_label}** için uygulanıyor...")

            _render_invite_test_controls(
                [{"TestAdi": active_test_name, "Dosya": active_test_file}],
                key_prefix="invite_direct",
                lead_label=lead_label,
                show_heading=False,
            )

            # Test tamamlama ve kapatma butonlari
            btn_col1, btn_col2 = st.columns(2)
            with btn_col1:
                if st.button("✅ Testi Tamamla ve Kaydet", key="invite_test_complete_direct", use_container_width=True):
                    # Testi adayin kaydina isle
                    save_candidate_test_result(
                        candidate_label=lead_label,
                        test_name=active_test_name,
                        test_file=active_test_file,
                        source="davet_uygulama_testleri"
                    )
                    st.success(f"✅ **{active_test_name}** testi **{lead_label}** için kaydedildi!")
                    st.balloons()
                    st.session_state["invite_test_active"] = None
                    st.session_state["invite_test_active_file"] = None
                    st.rerun()

            with btn_col2:
                if st.button("❌ Testi Kapat (Kaydetme)", key="invite_test_close_direct", use_container_width=True):
                    st.session_state["invite_test_active"] = None
                    st.session_state["invite_test_active_file"] = None
                    st.rerun()
    else:
        st.info("👆 Yukaridan bir aday secin ve test uygulayin.")

    st.markdown("---")
    st.markdown("### 📋 Kayıtli Testler")
    st.dataframe(pd.DataFrame(tests), use_container_width=True)
    delete_options = [
        f"{idx+1}. {item.get('TestAdi','')} ({item.get('Tarih','')})"
        for idx, item in enumerate(tests)
    ]
    delete_choice = st.selectbox(
        "Silinecek testi sec",
        ["Seciniz"] + delete_options,
        key="invite_test_delete_choice",
    )
    if st.button("Secili Testi Sil", key="invite_test_delete"):
        if delete_choice == "Seciniz":
            st.warning("Silmek için bir test secin.")
        else:
            delete_idx = delete_options.index(delete_choice)
            tests.pop(delete_idx)
            save_invite_tests(tests)
            st.success("Test silindi.")
            st.rerun()


