def render_middle_school_exam_test(prefix: str, *, lead_label: str = "") -> bytes | None:
    bank = _middle_school_exam_bank()
    st.markdown("#### Ortaokul Seviye Tespit Sınavı")
    if lead_label:
        st.caption(f"Aday: {lead_label}")
    from utils.shared_data import get_student_display_options as _hi_stu_ms
    _stu_opts_ms = _hi_stu_ms()
    if len(_stu_opts_ms) > 1:
        _stu_sel_ms = st.selectbox("Kayıtli ogrenci sec", list(_stu_opts_ms.keys()), key=f"{prefix}_stu_sel")
        _stu_data_ms = _stu_opts_ms.get(_stu_sel_ms, {})
    else:
        _stu_sel_ms = None
        _stu_data_ms = {}
    info_cols = st.columns(2)
    with info_cols[0]:
        student_name = st.text_input(
            "Öğrenci Ad Soyad",
            value=f'{_stu_data_ms.get("ad", "")} {_stu_data_ms.get("soyad", "")}'.strip() if _stu_data_ms else "",
            key=f"{prefix}_student_name",
        )
    with info_cols[1]:
        student_class = st.text_input(
            "Sınıf/Şube",
            value=f'{_stu_data_ms.get("sinif", "")}/{_stu_data_ms.get("sube", "")}' if _stu_data_ms.get("sinif") else "",
            key=f"{prefix}_student_class",
        )
    if not bank:
        st.info("Soru bankasi yuklenemedi.")
        return None
    start_key = f"{prefix}_exam_start_ts"
    started_key = f"{prefix}_exam_started"
    started = st.session_state.get(started_key, False)
    class_options = [bank[key]["label"] for key in bank.keys()]
    class_key_map = {bank[key]["label"]: key for key in bank.keys()}
    selected_label = st.selectbox(
        "Sınıf sec",
        class_options,
        key=f"{prefix}_class_select",
        disabled=started,
    )
    selected_key = class_key_map.get(selected_label, next(iter(bank.keys())))
    exam = bank.get(selected_key)
    if not exam:
        st.info("Sınav bulunamadı.")
        return None

    if not started:
        if st.button("Sınavı Baslat (80 dk)", key=f"{prefix}_start_exam"):
            st.session_state[started_key] = True
            st.session_state[start_key] = time_module.time()
            trigger_rerun()
        st.info("Sınav baslatilmadi.")
        return None

    start_ts = st.session_state.get(start_key)
    if not start_ts:
        start_ts = time_module.time()
        st.session_state[start_key] = start_ts
    elapsed = int(time_module.time() - start_ts)
    remaining = max(0, EXAM_DURATION_SECONDS - elapsed)
    minutes, seconds = divmod(remaining, 60)
    st.markdown(f"**Kalan Sure:** {minutes:02d}:{seconds:02d}")
    if remaining > 0:
        schedule_auto_rerun(1000)
    else:
        st.warning("Sınav suresi doldu.")

    options = ["Seciniz", "A", "B", "C", "D"]
    responses: list[tuple[str, str, str]] = []
    outcome_map: dict[str, list[tuple[str, str]]] = {}
    for subject in exam["subjects"]:
        q_count = len(subject["questions"])
        outcome_map[subject["name"]] = [
            _middle_school_outcome_for(subject["name"], idx + 1) for idx in range(q_count)
        ]

    for s_idx, subject in enumerate(exam["subjects"], start=1):
        questions = subject["questions"]
        with st.expander(f"{subject['name']} ({len(questions)} Soru)", expanded=s_idx == 1):
            for q_idx, (question, opt_a, opt_b, opt_c, opt_d, answer) in enumerate(questions, start=1):
                st.markdown(f"**{q_idx}.** {question}")
                st.caption(f"A) {opt_a}  |  B) {opt_b}  |  C) {opt_c}  |  D) {opt_d}")
                choice = st.selectbox(
                    "Cevap",
                    options,
                    key=f"{prefix}_{selected_key}_{subject['name']}_{q_idx}",
                    label_visibility="collapsed",
                    disabled=remaining <= 0,
                )
                responses.append((subject["name"], choice, answer))

    if st.button("Sonucu Hesapla", key=f"{prefix}_calc"):
        subject_rows: list[dict[str, Any]] = []
        total_correct = 0
        total_wrong = 0
        total_blank = 0
        total_net = 0.0
        total_questions = sum(len(subject["questions"]) for subject in exam["subjects"])
        outcome_stats: dict[tuple[str, str], dict[str, float]] = {}
        for subject in exam["subjects"]:
            questions = subject["questions"]
            correct = 0
            wrong = 0
            blank = 0
            for q_idx in range(1, len(questions) + 1):
                _, chosen, answer = responses.pop(0)
                outcome_code, outcome_desc = ("", "")
                mapped = outcome_map.get(subject["name"])
                if mapped and q_idx <= len(mapped):
                    outcome_code, outcome_desc = mapped[q_idx - 1]
                outcome_key = (outcome_code or "GEN-001", outcome_desc or "Genel kazanim")
                stats = outcome_stats.setdefault(
                    outcome_key, {"correct": 0.0, "total": 0.0}
                )
                stats["total"] += 1
                if chosen == "Seciniz":
                    blank += 1
                elif chosen == answer:
                    correct += 1
                    stats["correct"] += 1
                else:
                    wrong += 1
            net = correct - (wrong / 4)
            total_correct += correct
            total_wrong += wrong
            total_blank += blank
            total_net += net
            subject_rows.append(
                {
                    "Ders": subject["name"],
                    "Dogru": correct,
                    "Yanlis": wrong,
                    "Bos": blank,
                    "Net": f"{net:.2f}",
                }
            )

        base_score = 150.0
        points_per_question = 350 / total_questions if total_questions else 0
        total_score = base_score + max(0.0, total_net) * points_per_question
        total_score = min(500.0, total_score)
        summary_rows = [
            {"Kalem": "Toplam Dogru", "Deger": total_correct},
            {"Kalem": "Toplam Yanlis", "Deger": total_wrong},
            {"Kalem": "Toplam Bos", "Deger": total_blank},
            {"Kalem": "Toplam Net", "Deger": f"{total_net:.2f}"},
            {"Kalem": "Taban Puan", "Deger": f"{base_score:.0f}"},
            {"Kalem": "Toplam Puan (500)", "Deger": f"{total_score:.2f}"},
            {"Kalem": "Hesap", "Deger": "4 yanlis 1 dogru goturur"},
            {"Kalem": "Sınıf", "Deger": exam["label"]},
        ]
        outcome_rows: list[dict[str, Any]] = []
        for (code, desc), stats in outcome_stats.items():
            total = stats["total"] or 1
            pct = (stats["correct"] / total) * 100
            outcome_rows.append(
                {
                    "Kazanim Kodu": code,
                    "Kazanim": desc,
                    "Dogru": int(stats["correct"]),
                    "Toplam": int(stats["total"]),
                    "Başarı %": f"{pct:.0f}",
                }
            )
        outcome_rows.sort(key=lambda row: float(row["Başarı %"]))
        need_labels, need_values = _build_need_distribution(subject_rows)
        recommendation_rows = _build_subject_recommendations(subject_rows)

        st.markdown("### Sonuc Özeti")
        st.dataframe(pd.DataFrame(subject_rows), use_container_width=True, hide_index=True)
        st.dataframe(pd.DataFrame(summary_rows), use_container_width=True, hide_index=True)
        if outcome_rows:
            st.markdown("### Kazanim Başarı Tablosu")
            st.dataframe(pd.DataFrame(outcome_rows), use_container_width=True, hide_index=True)
        if recommendation_rows:
            st.markdown("### Ders Bazinda Oneriler")
            st.dataframe(pd.DataFrame(recommendation_rows), use_container_width=True, hide_index=True)

        labels = [row["Ders"] for row in subject_rows]
        values = [float(row["Dogru"]) for row in subject_rows]
        pdf_bytes = generate_level_exam_pdf(
            f"Ortaokul Seviye Tespit Sınavı - {exam['label']}",
            lead_label,
            subject_rows,
            summary_rows,
            labels,
            values,
            student_name=student_name.strip(),
            student_class=student_class.strip(),
            outcome_rows=outcome_rows,
            need_labels=need_labels,
            need_values=need_values,
            recommendation_rows=recommendation_rows,
        )
        if pdf_bytes:
            st.download_button(
                "PDF indir",
                pdf_bytes,
                file_name=f"ortaokul_seviye_tespit_{selected_key}.pdf",
                mime="application/pdf",
                key=f"{prefix}_pdf",
            )
        return pdf_bytes
    return None


