def render_high_school_exam_test(prefix: str, *, lead_label: str = "") -> bytes | None:
    bank = _high_school_exam_bank()
    st.markdown("#### Lise Seviye Tespit Sınavlari")
    if lead_label:
        st.caption(f"Aday: {lead_label}")
    from utils.shared_data import get_student_display_options as _hi_stu_hs
    _stu_opts_hs = _hi_stu_hs()
    if len(_stu_opts_hs) > 1:
        _stu_sel_hs = st.selectbox("Kayıtli ogrenci sec", list(_stu_opts_hs.keys()), key=f"{prefix}_stu_sel")
        _stu_data_hs = _stu_opts_hs.get(_stu_sel_hs, {})
    else:
        _stu_sel_hs = None
        _stu_data_hs = {}
    info_cols = st.columns(2)
    with info_cols[0]:
        student_name = st.text_input(
            "Öğrenci Ad Soyad",
            value=f'{_stu_data_hs.get("ad", "")} {_stu_data_hs.get("soyad", "")}'.strip() if _stu_data_hs else "",
            key=f"{prefix}_student_name",
        )
    with info_cols[1]:
        student_class = st.text_input(
            "Sınıf/Şube",
            value=f'{_stu_data_hs.get("sinif", "")}/{_stu_data_hs.get("sube", "")}' if _stu_data_hs.get("sinif") else "",
            key=f"{prefix}_student_class",
        )
    if not bank:
        st.info("Soru bankasi yuklenemedi.")
        return None
    start_key = f"{prefix}_exam_start_ts"
    started_key = f"{prefix}_exam_started"
    started = st.session_state.get(started_key, False)
    class_options = [bank[key]["label"] for key in bank.keys()]
    class_key_map = {bank[key]["label"]: key for key in bank.keys()}
    selected_label = st.selectbox(
        "Sınıf sec",
        class_options,
        key=f"{prefix}_class_select",
        disabled=started,
    )
    selected_key = class_key_map.get(selected_label, next(iter(bank.keys())))
    exam = bank.get(selected_key)
    if not exam:
        st.info("Sınav bulunamadı.")
        return None

    if not started:
        if st.button("Sınavı Baslat (80 dk)", key=f"{prefix}_start_exam"):
            st.session_state[started_key] = True
            st.session_state[start_key] = time_module.time()
            trigger_rerun()
        st.info("Sınav baslatilmadi.")
        return None

    start_ts = st.session_state.get(start_key)
    if not start_ts:
        start_ts = time_module.time()
        st.session_state[start_key] = start_ts
    elapsed = int(time_module.time() - start_ts)
    remaining = max(0, EXAM_DURATION_SECONDS - elapsed)
    minutes, seconds = divmod(remaining, 60)
    st.markdown(f"**Kalan Sure:** {minutes:02d}:{seconds:02d}")
    if remaining > 0:
        schedule_auto_rerun(1000)
    else:
        st.warning("Sınav suresi doldu.")

    options = ["Seciniz", "A", "B", "C", "D", "E"]
    responses: list[tuple[str, str, str]] = []
    outcome_map: dict[str, list[tuple[str, str]]] = {}
    grade_number = int(selected_key)
    for subject in exam["subjects"]:
        q_count = len(subject["questions"])
        outcomes = _high_school_outcomes_for(grade_number, subject["name"])
        if not outcomes:
            outcomes = [(f"{subject['name']} KZ-{idx+1:02d}", "Kazanim") for idx in range(q_count)]
        outcome_map[subject["name"]] = [
            outcomes[idx % len(outcomes)] for idx in range(q_count)
        ]

    for s_idx, subject in enumerate(exam["subjects"], start=1):
        questions = subject["questions"]
        with st.expander(f"{subject['name']} ({len(questions)} Soru)", expanded=s_idx == 1):
            for q_idx, (question, opt_a, opt_b, opt_c, opt_d, opt_e, answer) in enumerate(questions, start=1):
                st.markdown(f"**{q_idx}.** {question}")
                st.caption(
                    f"A) {opt_a}  |  B) {opt_b}  |  C) {opt_c}  |  D) {opt_d}  |  E) {opt_e}"
                )
                choice = st.selectbox(
                    "Cevap",
                    options,
                    key=f"{prefix}_{selected_key}_{subject['name']}_{q_idx}",
                    label_visibility="collapsed",
                    disabled=remaining <= 0,
                )
                responses.append((subject["name"], choice, answer))

    if st.button("Sonucu Hesapla", key=f"{prefix}_calc"):
        subject_rows: list[dict[str, Any]] = []
        total_correct = 0
        total_wrong = 0
        total_blank = 0
        total_net = 0.0
        total_questions = sum(len(subject["questions"]) for subject in exam["subjects"])
        outcome_stats: dict[tuple[str, str], dict[str, float]] = {}
        for subject in exam["subjects"]:
            questions = subject["questions"]
            correct = 0
            wrong = 0
            blank = 0
            for q_idx in range(1, len(questions) + 1):
                _, chosen, answer = responses.pop(0)
                outcome_code, outcome_desc = ("", "")
                mapped = outcome_map.get(subject["name"])
                if mapped and q_idx <= len(mapped):
                    outcome_code, outcome_desc = mapped[q_idx - 1]
                outcome_key = (outcome_code or "GEN-001", outcome_desc or "Genel kazanim")
                stats = outcome_stats.setdefault(
                    outcome_key, {"correct": 0.0, "total": 0.0}
                )
                stats["total"] += 1
                if chosen == "Seciniz":
                    blank += 1
                elif chosen == answer:
                    correct += 1
                    stats["correct"] += 1
                else:
                    wrong += 1
            net = correct - (wrong / 4)
            total_correct += correct
            total_wrong += wrong
            total_blank += blank
            total_net += net
            subject_rows.append(
                {
                    "Ders": subject["name"],
                    "Dogru": correct,
                    "Yanlis": wrong,
                    "Bos": blank,
                    "Net": f"{net:.2f}",
                }
            )

        base_score = 150.0
        points_per_question = 350 / total_questions if total_questions else 0
        total_score = base_score + max(0.0, total_net) * points_per_question
        total_score = min(500.0, total_score)
        summary_rows = [
            {"Kalem": "Toplam Dogru", "Deger": total_correct},
            {"Kalem": "Toplam Yanlis", "Deger": total_wrong},
            {"Kalem": "Toplam Bos", "Deger": total_blank},
            {"Kalem": "Toplam Net", "Deger": f"{total_net:.2f}"},
            {"Kalem": "Taban Puan", "Deger": f"{base_score:.0f}"},
            {"Kalem": "Toplam Puan (500)", "Deger": f"{total_score:.2f}"},
            {"Kalem": "Hesap", "Deger": "4 yanlis 1 dogru goturur"},
            {"Kalem": "Sınıf", "Deger": exam["label"]},
        ]
        outcome_rows: list[dict[str, Any]] = []
        for (code, desc), stats in outcome_stats.items():
            total = stats["total"] or 1
            pct = (stats["correct"] / total) * 100
            outcome_rows.append(
                {
                    "Kazanim Kodu": code,
                    "Kazanim": desc,
                    "Dogru": int(stats["correct"]),
                    "Toplam": int(stats["total"]),
                    "Başarı %": f"{pct:.0f}",
                }
            )
        outcome_rows.sort(key=lambda row: float(row["Başarı %"]))
        need_labels, need_values = _build_need_distribution(subject_rows)
        recommendation_rows = _build_subject_recommendations(subject_rows)

        st.markdown("### Sonuc Özeti")
        st.dataframe(pd.DataFrame(subject_rows), use_container_width=True, hide_index=True)
        st.dataframe(pd.DataFrame(summary_rows), use_container_width=True, hide_index=True)
        if outcome_rows:
            st.markdown("### Kazanim Başarı Tablosu")
            st.dataframe(pd.DataFrame(outcome_rows), use_container_width=True, hide_index=True)
        if recommendation_rows:
            st.markdown("### Ders Bazinda Oneriler")
            st.dataframe(pd.DataFrame(recommendation_rows), use_container_width=True, hide_index=True)

        labels = [row["Ders"] for row in subject_rows]
        values = [float(row["Dogru"]) for row in subject_rows]
        pdf_bytes = generate_level_exam_pdf(
            f"Lise Seviye Tespit Sınavı - {exam['label']}",
            lead_label,
            subject_rows,
            summary_rows,
            labels,
            values,
            student_name=student_name.strip(),
            student_class=student_class.strip(),
            outcome_rows=outcome_rows,
            need_labels=need_labels,
            need_values=need_values,
            recommendation_rows=recommendation_rows,
        )
        if pdf_bytes:
            st.download_button(
                "PDF indir",
                pdf_bytes,
                file_name=f"lise_seviye_tespit_{selected_key}.pdf",
                mime="application/pdf",
                key=f"{prefix}_pdf",
            )
        return pdf_bytes


def render_language_placement_exam_test(prefix: str, *, lead_label: str = "") -> bytes | None:
    bank = _language_placement_exam_bank()
    st.markdown("#### Yabanci Dil Olcum Sınavı (CEFR Placement)")
    if lead_label:
        st.caption(f"Aday: {lead_label}")
    from utils.shared_data import get_student_display_options as _hi_stu_lang
    _stu_opts_lang = _hi_stu_lang()
    if len(_stu_opts_lang) > 1:
        _stu_sel_lang = st.selectbox("Kayıtli ogrenci sec", list(_stu_opts_lang.keys()), key=f"{prefix}_stu_sel")
        _stu_data_lang = _stu_opts_lang.get(_stu_sel_lang, {})
    else:
        _stu_sel_lang = None
        _stu_data_lang = {}
    info_cols = st.columns(2)
    with info_cols[0]:
        student_name = st.text_input(
            "Öğrenci Ad Soyad",
            value=f'{_stu_data_lang.get("ad", "")} {_stu_data_lang.get("soyad", "")}'.strip() if _stu_data_lang else "",
            key=f"{prefix}_student_name",
        )
    with info_cols[1]:
        student_class = st.text_input(
            "Sınıf/Şube",
            value=f'{_stu_data_lang.get("sinif", "")}/{_stu_data_lang.get("sube", "")}' if _stu_data_lang.get("sinif") else "",
            key=f"{prefix}_student_class",
        )
    if not bank:
        st.info("Soru bankasi yuklenemedi.")
        return None

    level_options = [bank[key]["label"] for key in bank.keys()]
    level_key_map = {bank[key]["label"]: key for key in bank.keys()}
    selected_label = st.selectbox(
        "Kademe sec",
        level_options,
        key=f"{prefix}_level_select",
    )
    selected_key = level_key_map.get(selected_label, next(iter(bank.keys())))
    exam = bank.get(selected_key)
    if not exam:
        st.info("Sınav bulunamadı.")
        return None

    st.caption(f"CEFR hedef araligi: {exam.get('cefr', '')}")

    options = ["Seciniz", "A", "B", "C", "D"]
    responses: list[tuple[str, str, str]] = []
    section_totals: dict[str, int] = {}

    for section in exam["sections"]:
        name = section["name"]
        section_totals[name] = 0

    for s_idx, section in enumerate(exam["sections"], start=1):
        name = section["name"]
        q_counter = 0
        st.markdown(f"### {name}")
        if section["type"] == "listening":
            for b_idx, block in enumerate(section["blocks"], start=1):
                st.markdown(f"**{block['title']}**")
                render_tts_player(
                    block["text"],
                    key=f"{prefix}_tts_{selected_key}_{s_idx}_{b_idx}",
                )
                with st.expander("Metni goster", expanded=False):
                    st.write(block["text"])
                for question, opt_a, opt_b, opt_c, opt_d, answer in block["questions"]:
                    q_counter += 1
                    section_totals[name] += 1
                    st.markdown(f"**{q_counter}.** {question}")
                    st.caption(f"A) {opt_a}  |  B) {opt_b}  |  C) {opt_c}  |  D) {opt_d}")
                    choice = st.selectbox(
                        "Cevap",
                        options,
                        key=f"{prefix}_{selected_key}_{name}_{q_counter}",
                        label_visibility="collapsed",
                    )
                    responses.append((name, choice, answer))
        elif section["type"] == "reading":
            for b_idx, block in enumerate(section["blocks"], start=1):
                st.markdown(f"**{block['title']}**")
                st.info(block["text"])
                for question, opt_a, opt_b, opt_c, opt_d, answer in block["questions"]:
                    q_counter += 1
                    section_totals[name] += 1
                    st.markdown(f"**{q_counter}.** {question}")
                    st.caption(f"A) {opt_a}  |  B) {opt_b}  |  C) {opt_c}  |  D) {opt_d}")
                    choice = st.selectbox(
                        "Cevap",
                        options,
                        key=f"{prefix}_{selected_key}_{name}_{q_counter}",
                        label_visibility="collapsed",
                    )
                    responses.append((name, choice, answer))
        else:
            for question, opt_a, opt_b, opt_c, opt_d, answer in section["questions"]:
                q_counter += 1
                section_totals[name] += 1
                st.markdown(f"**{q_counter}.** {question}")
                st.caption(f"A) {opt_a}  |  B) {opt_b}  |  C) {opt_c}  |  D) {opt_d}")
                choice = st.selectbox(
                    "Cevap",
                    options,
                    key=f"{prefix}_{selected_key}_{name}_{q_counter}",
                    label_visibility="collapsed",
                )
                responses.append((name, choice, answer))

    if st.button("Sonucu Hesapla", key=f"{prefix}_calc"):
        stats = {
            name: {"correct": 0, "wrong": 0, "blank": 0, "total": 0}
            for name in section_totals.keys()
        }
        total_correct = 0
        total_wrong = 0
        total_blank = 0
        total_questions = len(responses)
        for section_name, choice, answer in responses:
            row = stats[section_name]
            row["total"] += 1
            if choice == "Seciniz":
                row["blank"] += 1
                total_blank += 1
            elif choice == answer:
                row["correct"] += 1
                total_correct += 1
            else:
                row["wrong"] += 1
                total_wrong += 1

        total_net = total_correct - (total_wrong / 4)
        total_pct = (total_correct / total_questions * 100) if total_questions else 0.0

        def cefr_band(total_pct_value: float, level_key: str) -> tuple[str, str]:
            bands = {
                "primary": [
                    (39, "Pre-A1", "Temel kelime ve kaliplarla sinirli iletisim."),
                    (59, "A1", "Basit kaliplarla temel iletisim kurabilir."),
                    (79, "A1+", "Basit metinleri daha rahat anlar, kisa iletisim kurar."),
                    (100, "A2", "Günlük konularda daha akici iletisim kurabilir."),
                ],
                "middle": [
                    (39, "A1", "Temel iletisim için destek gerekir."),
                    (59, "A2", "Günlük kaliplarda daha rahattir."),
                    (79, "A2+/B1", "Baglamla birlikte daha bagimsiz okuyup dinleyebilir."),
                    (100, "B1", "Bagimsiz iletisim ve daha uzun metinlerde yeterli."),
                ],
                "high": [
                    (29, "A2", "Temel seviye, gelisim için yogun tekrar gerekir."),
                    (49, "B1", "Günlük ve akademik metinlerde temel yeterlilik."),
                    (69, "B1+/B2", "Akici okuma ve daha kompleks metinlerde ilerleme."),
                    (84, "B2", "Akademik ve uzun metinlerde yeterli bagimsizlik."),
                    (100, "C1", "Yuksek seviye, akici ve dogal dil kullanimina yakin."),
                ],
            }
            for max_pct, level_name, note in bands.get(level_key, []):
                if total_pct_value <= max_pct:
                    return level_name, note
            return "A1", "Seviye belirlenemedi."

        def section_recommendation(section_name: str, pct_value: float) -> str:
            if pct_value < 50:
                return (
                    "Temel tekrar + kisa calisma bloklari. Günde 15-20 dk hedefe odakli pratik."
                )
            if pct_value < 70:
                return (
                    "Gelisim için haftalik 3-4 mini calisma. Zayif konularda kisa tekrar."
                )
            return "Seviyeyi korumak için duzenli okuma/dinleme ve haftalik tekrar."

        cefr_level, cefr_note = cefr_band(total_pct, selected_key)
        summary_rows = [
            {"Kalem": "Toplam Soru", "Deger": str(total_questions)},
            {"Kalem": "Dogru", "Deger": str(total_correct)},
            {"Kalem": "Yanlis", "Deger": str(total_wrong)},
            {"Kalem": "Bos", "Deger": str(total_blank)},
            {"Kalem": "Net", "Deger": f"{total_net:.2f}"},
            {"Kalem": "Başarı %", "Deger": f"{total_pct:.0f}%"},
            {"Kalem": "CEFR Hedef Araligi", "Deger": exam.get("cefr", "")},
            {"Kalem": "Tahmini CEFR", "Deger": cefr_level},
        ]

        subject_rows: list[dict[str, Any]] = []
        labels: list[str] = []
        values: list[float] = []
        recommendation_rows: list[dict[str, Any]] = []
        section_pies: list[tuple[str, list[str], list[float]]] = []
        for section_name, row in stats.items():
            correct = row["correct"]
            wrong = row["wrong"]
            blank = row["blank"]
            total = row["total"]
            net = correct - (wrong / 4)
            pct = (correct / total * 100) if total else 0.0
            subject_rows.append(
                {
                    "Bolum": section_name,
                    "Dogru": correct,
                    "Yanlis": wrong,
                    "Bos": blank,
                    "Net": f"{net:.2f}",
                    "Başarı %": f"{pct:.0f}%",
                }
            )
            labels.append(section_name)
            values.append(correct)
            recommendation_rows.append(
                {
                    "Bolum": section_name,
                    "Oneri": section_recommendation(section_name, pct),
                }
            )
            section_pies.append(
                (
                    section_name,
                    ["Dogru", "Yanlis/Bos"],
                    [float(correct), float(wrong + blank)],
                )
            )

        st.markdown("### Özet")
        st.dataframe(pd.DataFrame(summary_rows), use_container_width=True)
        st.info(f"Tahmini CEFR: **{cefr_level}** â {cefr_note}")
        st.markdown("### Bolum Bazli Sonuc")
        st.dataframe(pd.DataFrame(subject_rows), use_container_width=True)
        if labels and values:
            plot_pie(dict(zip(labels, values)), "Bolum Dagilimi")
        st.markdown("### Bolum Bazli Oneriler")
        st.dataframe(pd.DataFrame(recommendation_rows), use_container_width=True)

        pdf_bytes = generate_level_exam_pdf(
            f"Yabanci Dil Olcum Sınavı - {exam['label']}",
            lead_label,
            subject_rows,
            summary_rows,
            labels,
            values,
            student_name=student_name,
            student_class=student_class,
            recommendation_rows=recommendation_rows,
            section_pies=section_pies,
        )
        if pdf_bytes:
            st.download_button(
                "PDF indir",
                pdf_bytes,
                file_name=f"yabanci_dil_olcum_{selected_key}.pdf",
                mime="application/pdf",
                key=f"{prefix}_pdf",
            )
        return pdf_bytes


def render_vark_learning_style_test(
    prefix: str,
    *,
    lead_label: str = "",
    title: str = "Ogrenme Stili Testi (7-9 Yas) - VARK",
    questions: list[dict[str, Any]] | None = None,
) -> None:
    if questions is None:
        questions = _vark_test_bank()
    st.markdown(f"#### {title}")
    if lead_label:
        st.caption(f"Aday: {lead_label}")

    options = ["Seciniz", "A", "B", "C", "D"]
    responses: list[tuple[str, str]] = []
    for idx, item in enumerate(questions, start=1):
        st.markdown(f"**{idx}.** {item['text']}")
        st.caption(
            "A) {0}  |  B) {1}  |  C) {2}  |  D) {3}".format(
                item["options"][0][1],
                item["options"][1][1],
                item["options"][2][1],
                item["options"][3][1],
            )
        )
        choice = st.selectbox(
            "Cevap",
            options,
            key=f"{prefix}_vark_{idx}",
            label_visibility="collapsed",
        )
        responses.append((choice, item["id"]))

    if st.button("Sonucu Hesapla", key=f"{prefix}_vark_calc"):
        counts = {"V": 0, "A": 0, "R": 0, "K": 0}
        total = 0
        for (choice, _), item in zip(responses, questions):
            if choice == "Seciniz":
                continue
            total += 1
            for opt_key, _, style in item["options"]:
                if opt_key == choice:
                    counts[style] += 1
                    break

        if total == 0:
            st.info("Sonuc hesaplamak için cevaplari isaretleyin.")
            return

        percents = {
            "V": int(round(counts["V"] / total * 100)) if total else 0,
            "A": int(round(counts["A"] / total * 100)) if total else 0,
            "R": int(round(counts["R"] / total * 100)) if total else 0,
            "K": int(round(counts["K"] / total * 100)) if total else 0,
        }

        st.markdown("### Özet")
        summary_rows = [
            {"Stil": "Gorsel (V)", "Puan": counts["V"]},
            {"Stil": "Isitsel (A)", "Puan": counts["A"]},
            {"Stil": "Okuma/Yazma (R)", "Puan": counts["R"]},
            {"Stil": "Kinestetik (K)", "Puan": counts["K"]},
            {"Stil": "V %", "Puan": f"%{percents['V']}"},
            {"Stil": "A %", "Puan": f"%{percents['A']}"},
            {"Stil": "R %", "Puan": f"%{percents['R']}"},
            {"Stil": "K %", "Puan": f"%{percents['K']}"},
        ]
        st.dataframe(pd.DataFrame(summary_rows), use_container_width=True)

        max_score = max(counts.values()) if counts else 0
        top_styles = [k for k, v in counts.items() if v == max_score and max_score > 0]
        style_names = {
            "V": "Gorsel (V)",
            "A": "Isitsel (A)",
            "R": "Okuma/Yazma (R)",
            "K": "Kinestetik (K)",
        }
        secondary_styles: list[str] = []
        label = "Tekil Stil"
        primary = "/".join(style_names.get(s, s) for s in top_styles) if top_styles else "-"
        remaining_scores = {
            k: v for k, v in counts.items() if k not in top_styles
        }
        if remaining_scores:
            second_score = max(remaining_scores.values())
            secondary_styles = [k for k, v in remaining_scores.items() if v == second_score]
        secondary = "/".join(style_names.get(s, s) for s in secondary_styles) if secondary_styles else "-"
        if len(top_styles) > 1:
            label = "Çoklu Stil"
        elif secondary_styles:
            diff = max_score - remaining_scores.get(secondary_styles[0], 0)
            if diff <= 3:
                label = "Çoklu Stil"

        if top_styles:
            st.info(
                "Baskin stil(ler): "
                + ", ".join(style_names.get(s, s) for s in top_styles)
            )
        st.markdown(
            f"**Birincil Stil:** {primary}  \n"
            f"**Ikincil Stil:** {secondary}  \n"
            f"**Etiket:** {label}"
        )
        plot_pie(
            {
                "Gorsel (V)": counts["V"],
                "Isitsel (A)": counts["A"],
                "Okuma/Yazma (R)": counts["R"],
                "Kinestetik (K)": counts["K"],
            },
            "VARK Dagilimi",
        )
        recommendation_map = {
            "V": [
                "Zihin haritasi/semalar ve renk kodlu ozetler kullan.",
                "Gorsel kartlarla tekrar yap (kavram + ikon).",
                "Grafik/tablo ile konuyu bagla.",
            ],
            "A": [
                "Konuyu sesli anlat/tekrar et (teach-back).",
                "Dinleme calismalarina zaman ayir (podcast/ses kaydi).",
                "Soru-cevap ile ogrenmeyi pekistir.",
            ],
            "R": [
                "Özet cikart, anahtar kelimeleri yaz.",
                "Kavram sozlugu olustur (terim + kisa aciklama).",
                "Metin uzerinde isaretleme ve tekrar.",
            ],
            "K": [
                "Ornek soru/cozum ve uygulama odakli calis.",
                "Kisa calisma + mini uygulama dongusu kur.",
                "Somut materyal/deney ile ogren.",
            ],
        }
        if top_styles:
            st.markdown("### Oneriler (Baskin Stiller)")
            for style in top_styles:
                st.markdown(f"**{style_names.get(style, style)}**")
                for line in recommendation_map.get(style, []):
                    st.write(f"- {line}")
        pdf_bytes = generate_vark_pdf(
            title,
            lead_label,
            counts,
            total,
            top_styles,
            percents,
            primary,
            secondary,
            label,
        )
        if pdf_bytes:
            st.download_button(
                "PDF indir",
                pdf_bytes,
                file_name="vark_ogrenme_stili_raporu.pdf",
                mime="application/pdf",
                key=f"{prefix}_vark_pdf",
            )


def render_hht1_test(prefix: str, *, lead_label: str = "") -> bytes | None:
    st.markdown("#### 1. Sınıf Hazirbulunusluk Tarama Testi (HHT-1)")
    st.caption("Sure: 12-18 dk (Öğrenci) + 5-7 dk (Veli) | Veli ogrenci bolumunde yonlendirme yapmaz.")
    if lead_label:
        st.caption(f"Aday: {lead_label}")

    from utils.shared_data import get_student_display_options as _hi_stu_hht
    _stu_opts_hht = _hi_stu_hht()
    if len(_stu_opts_hht) > 1:
        _stu_sel_hht = st.selectbox("Kayıtli ogrenci sec", list(_stu_opts_hht.keys()), key=f"{prefix}_stu_sel")
        _stu_data_hht = _stu_opts_hht.get(_stu_sel_hht, {})
    else:
        _stu_sel_hht = None
        _stu_data_hht = {}
    info_cols = st.columns(2)
    with info_cols[0]:
        student_name = st.text_input(
            "Öğrenci Ad Soyad",
            value=f'{_stu_data_hht.get("ad", "")} {_stu_data_hht.get("soyad", "")}'.strip() if _stu_data_hht else "",
            key=f"{prefix}_student_name",
        )
    with info_cols[1]:
        student_class = st.text_input(
            "Sınıf/Şube",
            value=f'{_stu_data_hht.get("sinif", "")}/{_stu_data_hht.get("sube", "")}' if _stu_data_hht.get("sinif") else "",
            key=f"{prefix}_student_class",
        )

    st.markdown("### A) Öğrenci Bolumu (S1-S25)")
    student_questions = _hht1_student_questions()
    student_answers: list[tuple[str, str]] = []
    options = ["Seciniz", "A", "B", "C", "D"]
    for idx, (question, opt_a, opt_b, opt_c, opt_d, answer) in enumerate(
        student_questions, start=1
    ):
        st.markdown(f"**S{idx}.** {question}")
        st.caption(f"A) {opt_a}  |  B) {opt_b}  |  C) {opt_c}  |  D) {opt_d}")
        choice = st.selectbox(
            "Cevap",
            options,
            key=f"{prefix}_student_{idx}",
            label_visibility="collapsed",
        )
        student_answers.append((choice, answer))

    st.markdown("### B) Veli Bolumu (S26-S40)")
    parent_items = _hht1_parent_items()
    parent_scale = ["Seciniz", "A", "B", "C", "D"]
    parent_map = {"A": 0, "B": 1, "C": 2, "D": 3}
    parent_choices: list[str] = []
    for idx, item in enumerate(parent_items, start=26):
        st.markdown(f"**S{idx}.** {item}")
        choice = st.selectbox(
            "Secim",
            parent_scale,
            key=f"{prefix}_parent_{idx}",
            label_visibility="collapsed",
        )
        parent_choices.append(choice)

    if st.button("Sonucu Hesapla", key=f"{prefix}_calc"):
        student_score = 0
        domain_map = {
            "Dil/Okuma": set(range(1, 8)),
            "Matematik/Sayılar": set(range(8, 15)),
            "Bilissel/Dikkat": set(range(15, 21)),
            "Sosyal/Uyum": set(range(21, 26)),
        }
        domain_correct = {key: 0 for key in domain_map.keys()}
        for idx, (chosen, answer) in enumerate(student_answers, start=1):
            if chosen == answer:
                student_score += 1
                for domain, items in domain_map.items():
                    if idx in items:
                        domain_correct[domain] += 1
                        break
        parent_score = 0
        for choice in parent_choices:
            parent_score += parent_map.get(choice, 0)
        total_score = student_score + parent_score
        percent = int(round((total_score / 70) * 100))
        if percent >= 75:
            level = "Hazir"
            suggestion = (
                "Okul rutinlerine yumusak gecis + okuma/sayi oyunlari ile surekli pekistirme."
            )
        elif percent >= 55:
            level = "Gelismekte"
            suggestion = (
                "Günlük 10 dk ses/hece + 10 dk sayi calismasi + dikkat oyunlari ile destek."
            )
        else:
            level = "Destek gerekli"
            suggestion = (
                "Kisa odakli calisma, temel dil/sayi becerileri ve aile-okul is birligiyle planli destek."
            )

        summary_rows = [
            {"Kalem": "Öğrenci Bolumu", "Deger": f"{student_score}/25"},
            {"Kalem": "Veli Gozlem Bolumu", "Deger": f"{parent_score}/45"},
            {"Kalem": "Toplam", "Deger": f"{total_score}/70"},
            {"Kalem": "Yuzde", "Deger": f"%{percent}"},
            {"Kalem": "Seviye", "Deger": level},
        ]
        domain_rows: list[dict[str, Any]] = []
        for domain, items in domain_map.items():
            max_points = len(items)
            correct = domain_correct.get(domain, 0)
            pct = int(round((correct / max_points) * 100)) if max_points else 0
            domain_rows.append(
                {
                    "Alan": domain,
                    "Dogru": f"{correct}/{max_points}",
                    "Başarı %": f"%{pct}",
                }
            )
        st.markdown("### Özet")
        st.dataframe(pd.DataFrame(summary_rows), use_container_width=True)
        st.markdown("### Alan Bazli Başarı (Öğrenci)")
        st.dataframe(pd.DataFrame(domain_rows), use_container_width=True)
        st.info(f"Genel Sonuc: %{percent} - {level}")
        support_lines: list[str] = []
        for row in domain_rows:
            pct_value = int(str(row["Başarı %"]).replace("%", "") or "0")
            if pct_value < 60:
                if row["Alan"] == "Dil/Okuma":
                    support_lines.append("Dil/Okuma: 2 hafta boyunca gunluk 10 dk ses/hece oyunlari + kelime calismasi.")
                elif row["Alan"] == "Matematik/Sayılar":
                    support_lines.append("Matematik/Sayılar: 2 hafta gunluk 10 dk sayma, eslestirme ve basit islem oyunu.")
                elif row["Alan"] == "Bilissel/Dikkat":
                    support_lines.append("Bilissel/Dikkat: 2 hafta kisa odak oyunlari + sekil/desen tamamlama.")
                else:
                    support_lines.append("Sosyal/Uyum: 2 hafta sira bekleme/kurala uyma + empati oyunlari.")
        if support_lines:
            suggestion = " ".join(support_lines)
        st.markdown(f"**Oneri (otomatik):** {suggestion}")

        pdf_bytes = generate_hht1_pdf(
            lead_label,
            student_name,
            student_class,
            student_score,
            parent_score,
            total_score,
            percent,
            level,
            suggestion,
            domain_rows=domain_rows,
        )
        if pdf_bytes:
            st.download_button(
                "PDF indir",
                pdf_bytes,
                file_name="hht1_sonuc_raporu.pdf",
                mime="application/pdf",
                key=f"{prefix}_pdf",
            )
        return pdf_bytes
    return None
    return None


