            c.setFillColor(HexColor("#1f2937"))
            c.setFont(font_name, 9)
            yorum_lines = safe_text(toplam_yorum)
            # Wrap text
            max_chars = 90
            for i in range(0, len(yorum_lines), max_chars):
                line = yorum_lines[i:i+max_chars]
