            y -= 0.5*cm

            # C) Öğrenme Profili
            c.setFillColor(HexColor("#f59e0b"))
            c.roundRect(1.5*cm, y - 0.8*cm, width - 3*cm, 1*cm, 5, fill=1, stroke=0)
