    # ==================== GÖRÜŞME SONUÇ DAĞILIMI ====================
    st.markdown('<p class="section-title">🤝 Görüşme Sonuç Dağılımı</p>', unsafe_allow_html=True)

    sonuc_counter: Counter = Counter()
    for result in meeting_results:
        sonuc = result.get("result", "Belirtilmemiş")
