    st.markdown("---")

    # ==================== PERSONEL PERFORMANSI ====================
    st.markdown('<p class="section-title">👤 Personel Performansı</p>', unsafe_allow_html=True)

    # Arama yapan personeller - Detaylı analiz
    arama_personel: Counter = Counter()
    arama_randevu: Counter = Counter()
    for label, entries in tracking_history.items():
        for entry in entries:
            owner = entry.get("owner", "Belirtilmemiş")
            if owner:
                arama_personel[owner] += 1
                result = normalize_followup_result(entry.get("result", ""))
                if result in FOLLOWUP_BOOKED_RESULTS:
                    arama_randevu[owner] += 1

    # Görüşme yapan personeller - Detaylı analiz
    gorusme_personel: Counter = Counter()
    gorusme_kayit: Counter = Counter()
    gorusme_fiyat: Counter = Counter()
    gorusme_olumsuz: Counter = Counter()
    for result in meeting_results:
        interviewer = result.get("interviewer", "") or result.get("owner", "Belirtilmemiş")
        if interviewer:
            gorusme_personel[interviewer] += 1
            meeting_result = result.get("result", "")
            if meeting_result == "Kayıt oldu":
                gorusme_kayit[interviewer] += 1
            elif meeting_result in ["Fiyat hesapla", "Fiyat verildi"]:
                gorusme_fiyat[interviewer] += 1
            elif meeting_result == "Kayıt olumsuz sonuçlandı":
                gorusme_olumsuz[interviewer] += 1

    # ===== BİRLEŞİK PERSONEL PERFORMANS TABLOSU =====
    st.markdown("#### 👥 Birleşik Personel Performans Analizi")

    # Tüm personelleri birleştir
    tum_personeller = set(arama_personel.keys()) | set(gorusme_personel.keys())

    if tum_personeller:
        birlesik_perf_data = []
        for personel in tum_personeller:
            arama_sayi = arama_personel.get(personel, 0)
            randevu_sayi = arama_randevu.get(personel, 0)
            randevu_oran = (randevu_sayi / arama_sayi * 100) if arama_sayi > 0 else 0

            gorusme_sayi = gorusme_personel.get(personel, 0)
            kayit = gorusme_kayit.get(personel, 0)
            fiyat = gorusme_fiyat.get(personel, 0)
            olumsuz = gorusme_olumsuz.get(personel, 0)
            kayit_oran = (kayit / gorusme_sayi * 100) if gorusme_sayi > 0 else 0

            # Toplam puan hesapla (ağırlıklı)
            toplam_puan = arama_sayi + (randevu_sayi * 2) + (gorusme_sayi * 3) + (kayit * 10)

            birlesik_perf_data.append({
                "Personel": personel[:25],
                "Arama": arama_sayi,
                "Randevu": randevu_sayi,
                "Rnv%": f"{randevu_oran:.0f}%",
                "Görüşme": gorusme_sayi,
                "Fiyat": fiyat,
                "Kayıt": kayit,
                "Olumsuz": olumsuz,
                "Kyt%": f"{kayit_oran:.0f}%",
                "Puan": toplam_puan
            })

        # Puana göre sırala
        birlesik_perf_data.sort(key=lambda x: x["Puan"], reverse=True)
        birlesik_perf_df = pd.DataFrame(birlesik_perf_data)
        st.dataframe(birlesik_perf_df, use_container_width=True, hide_index=True)

        # Personel puan sütun grafiği
        try:
            import plotly.graph_objects as go
            from utils.chart_utils import sc_bar, SC_CHART_CFG, SC_COLORS
            top_n = birlesik_perf_data[:10]
            if top_n:
                p_names = [p["Personel"] for p in top_n]
                p_puanlar = [p["Puan"] for p in top_n]
                fig_perf = go.Figure(data=[go.Bar(
                    x=p_names, y=p_puanlar,
                    marker_color=SC_COLORS[:len(p_names)],
                    text=p_puanlar, textposition="outside",
                )])
                sc_bar(fig_perf, height=280)
                fig_perf.update_layout(xaxis_tickangle=-45, margin=dict(b=60))
                st.plotly_chart(fig_perf, use_container_width=True, config=SC_CHART_CFG)
        except ImportError:
            pass

        # En iyi performanslar
        col_best1, col_best2 = st.columns(2)
        with col_best1:
            # En iyi arama performansı
            arama_yapanlar = [p for p in birlesik_perf_data if p["Arama"] >= 5]
            if arama_yapanlar:
                best_arama = max(arama_yapanlar, key=lambda x: float(x["Rnv%"].replace("%", "")))
                st.success(f"📞 **En İyi Randevu Oranı:** {best_arama['Personel']} ({best_arama['Rnv%']})")

        with col_best2:
            # En iyi görüşme performansı
            gorusme_yapanlar = [p for p in birlesik_perf_data if p["Görüşme"] >= 3]
            if gorusme_yapanlar:
                best_gorusme = max(gorusme_yapanlar, key=lambda x: float(x["Kyt%"].replace("%", "")))
                st.success(f"🤝 **En İyi Kayıt Oranı:** {best_gorusme['Personel']} ({best_gorusme['Kyt%']})")

        # Grafikler yan yana
        graf_col1, graf_col2 = st.columns(2)
        with graf_col1:
            if len(arama_personel) > 1:
                plot_pie(dict(arama_personel.most_common(8)), "Arama Dağılımı")
        with graf_col2:
            if len(gorusme_personel) > 1:
                plot_pie(dict(gorusme_personel.most_common(8)), "Görüşme Dağılımı")
    else:
        st.info("Personel verisi bulunamadı.")

    st.markdown("---")

    # ==================== AYLIK TREND ====================
    if gosterim_modu == "Detaylı":
        st.markdown('<p class="section-title">📅 Aylık Trend Analizi</p>', unsafe_allow_html=True)

        # Aylık aday sayıları
        aylik_aday: dict[str, int] = {ay: 0 for ay in donem_secenekleri[1:]}
        for lead in [l for l in leads if l.get("egitim_yili", "2025-2026") == selected_egitim_yili]:
            created_dt = _get_lead_creation_datetime(lead)
            if created_dt:
                ay_adi = donem_secenekleri[created_dt.month]
                aylik_aday[ay_adi] += 1

        aylik_df = pd.DataFrame([
            {"Ay": ay, "Aday Sayısı": sayi}
            for ay, sayi in aylik_aday.items()
        ])

        st.dataframe(aylik_df, use_container_width=True, hide_index=True)

        # Çubuk grafik
        if any(aylik_aday.values()):
            try:
                import plotly.graph_objects as go
                from utils.chart_utils import sc_bar, SC_CHART_CFG, SC_COLORS
                aylar = list(aylik_aday.keys())
                degerler = list(aylik_aday.values())
                bar_colors = [SC_COLORS[0] if v >= 5 else SC_COLORS[3] if v >= 1 else "#cbd5e1" for v in degerler]
                fig = go.Figure(data=[go.Bar(
                    x=aylar, y=degerler,
                    marker_color=bar_colors,
                    text=degerler, textposition="outside",
                )])
                sc_bar(fig, height=300)
                fig.update_layout(xaxis_tickangle=-45, margin=dict(b=60))
                st.plotly_chart(fig, use_container_width=True, config=SC_CHART_CFG)
            except ImportError:
                import matplotlib.pyplot as plt
                fig, ax = plt.subplots(figsize=(10, 4))
