            c.rect(1.5*cm, y - 0.6*cm, width - 3*cm, 0.8*cm, fill=True)
            c.setFillColorRGB(1, 1, 1)
            c.setFont(font_bold, 12)
            c.drawString(2*cm, y - 0.4*cm, "5. MECRA PERFORMANS ANALIZI")
            c.setFillColorRGB(0, 0, 0)
