            c.drawString(12*cm, y - 0.35*cm, "Görüşme")
            c.drawString(14*cm, y - 0.35*cm, "Grs%")
            c.drawString(16*cm, y - 0.35*cm, "Kayıt")
            c.drawString(17.8*cm, y - 0.35*cm, "Kyt%")
