            c.setFillColorRGB(0, 0, 0)
            y -= 0.5*cm

            # ===== SAYFA 3: DEMOGRAFİK DAĞILIM =====
            y = new_page()
            c.setFont(font_bold, 14)
            c.drawString(2*cm, y, "7. DEMOGRAFIK DAGILIM")
